export interface Question {
  id: string;
  course: string;
  subject: string;
  topic: string;
  questionText: string;
  options: string[];
  correctIndex: number;
  explanation: string;
  order: number;
  createdAt: number;
}

export interface AppDatabase {
  questions: Question[];
}

export type ViewType = 'HOME' | 'SUBJECTS' | 'TOPICS' | 'QUIZ' | 'ADMIN';

export interface NavigationState {
  view: ViewType;
  selectedCourse?: string;
  selectedSubject?: string;
  selectedTopic?: string;
}

export interface CourseStructure {
  name: string;
  subjects: string[];
  icon: string;
  color: string;
}

