export default SubjectsView;

import React, { useMemo } from 'react';
import { Question } from '../types';

interface TopicsViewProps {
  subjectName: string;
  questions: Question[];
  onSelectTopic: (topic: string) => void;
  onDeleteTopic: (topic: string) => void;
  onMoveTopic: (topic: string, direction: 'UP' | 'DOWN') => void;
}

const TopicsView: React.FC<TopicsViewProps> = ({ 
  subjectName, 
  questions, 
  onSelectTopic, 
  onDeleteTopic, 
  onMoveTopic 
}) => {
  const topics = useMemo(() => {
    const grouped = questions.reduce((acc, q) => {
      if (!acc[q.topic]) {
        acc[q.topic] = {
          name: q.topic,
          count: 0,
          order: q.order ?? 999
        };
      }
      acc[q.topic].count++;
      return acc;
    }, {} as Record<string, { name: string, count: number, order: number }>);

    return Object.values(grouped).sort((a, b) => a.order - b.order);
  }, [questions]);

  return (
    <div>
      <div className="flex justify-between items-end mb-8 border-b pb-4">
        <div>
          <p className="text-indigo-600 font-bold uppercase tracking-widest text-xs mb-1">Materia</p>
          <h2 className="text-3xl font-bold text-gray-800">{subjectName}</h2>
        </div>
        <div className="text-right text-gray-400 text-sm">
          {topics.length} temas registrados
        </div>
      </div>

      {topics.length === 0 ? (
        <div className="bg-gray-50 rounded-2xl border-2 border-dashed border-gray-200 p-12 text-center">
          <div className="text-5xl mb-4">📭</div>
          <h3 className="text-lg font-medium text-gray-600">No hay temas registrados aún</h3>
          <p className="text-gray-400 mt-2">Ve al Panel de Admin para crear la primera práctica.</p>
        </div>
      ) : (
        <div className="space-y-4">
          {topics.map((topic, index) => (
            <div 
              key={topic.name}
              className="bg-white rounded-xl shadow-sm border border-gray-100 p-5 flex flex-col md:flex-row items-center gap-6 hover:border-indigo-200 transition-colors"
            >
              <div className="bg-indigo-50 text-indigo-700 w-12 h-12 rounded-lg flex items-center justify-center font-black text-lg shrink-0">
                {topic.order === 999 ? '?' : topic.order}
              </div>

              <div className="flex-grow text-center md:text-left">
                <h4 className="text-xl font-bold text-gray-800">{topic.name}</h4>
                <p className="text-gray-400 text-sm">{topic.count} preguntas en este banco</p>
              </div>

              <div className="flex flex-wrap items-center justify-center gap-2 shrink-0">
                <div className="flex border rounded-lg overflow-hidden bg-gray-50">
                  <button 
                    onClick={() => onMoveTopic(topic.name, 'UP')}
                    disabled={index === 0}
                    className="p-2 hover:bg-gray-200 disabled:opacity-30 disabled:hover:bg-gray-50 transition-colors"
                    title="Mover Arriba"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                      <path fillRule="evenodd" d="M14.707 12.707a1 1 0 01-1.414 0L10 9.414l-3.293 3.293a1 1 0 01-1.414-1.414l4-4a1 1 0 011.414 0l4 4a1 1 0 010 1.414z" clipRule="evenodd" />
                    </svg>
                  </button>
                  <button 
                    onClick={() => onMoveTopic(topic.name, 'DOWN')}
                    disabled={index === topics.length - 1}
                    className="p-2 border-l hover:bg-gray-200 disabled:opacity-30 disabled:hover:bg-gray-50 transition-colors"
                    title="Mover Abajo"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                      <path fillRule="evenodd" d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z" clipRule="evenodd" />
                    </svg>
                  </button>
                </div>

                <button 
                  onClick={() => onSelectTopic(topic.name)}
                  className="bg-indigo-600 text-white px-5 py-2.5 rounded-lg text-sm font-bold hover:bg-indigo-700 active:scale-95 transition-all shadow-sm flex items-center gap-2"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
                  </svg>
                  Iniciar Quiz
                </button>

                <button 
                  onClick={() => onDeleteTopic(topic.name)}
                  className="p-2.5 text-rose-500 hover:bg-rose-50 rounded-lg transition-colors"
                  title="Eliminar Práctica"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                  </svg>
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default TopicsView;

import React, { useState } from 'react';
import { Question } from '../types';

interface QuizViewProps {
  topicName: string;
  questions: Question[];
}

const QuizView: React.FC<QuizViewProps> = ({ topicName, questions }) => {
  const [answers, setAnswers] = useState<Record<string, number>>({});
  const [isFinished, setIsFinished] = useState(false);

  const handleSelect = (qId: string, optIndex: number) => {
    if (isFinished) return;
    setAnswers(prev => ({ ...prev, [qId]: optIndex }));
  };

  const calculateScore = () => {
    let score = 0;
    questions.forEach(q => {
      if (answers[q.id] === q.correctIndex) score++;
    });
    return score;
  };

  const score = calculateScore();

  return (
    <div className="max-w-4xl mx-auto">
      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6 mb-8 sticky top-[80px] z-40 flex flex-col md:flex-row items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-black text-gray-800">{topicName}</h2>
          <p className="text-gray-400 text-sm">Contesta todas las preguntas para ver tus resultados.</p>
        </div>
        {!isFinished ? (
          <button 
            onClick={() => setIsFinished(true)}
            className="w-full md:w-auto bg-indigo-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-indigo-700 shadow-md active:scale-95 transition-all"
          >
            Calificar Simulacro
          </button>
        ) : (
          <div className="text-center px-6 py-2 bg-indigo-50 border border-indigo-200 rounded-xl">
            <span className="text-xs uppercase font-black text-indigo-400 block tracking-widest">Puntaje Final</span>
            <span className="text-3xl font-black text-indigo-700">{score} / {questions.length}</span>
          </div>
        )}
      </div>

      <div className="space-y-8 pb-12">
        {questions.map((q, idx) => {
          const selected = answers[q.id];
          const isCorrect = selected === q.correctIndex;

          return (
            <div key={q.id} className="bg-white rounded-2xl border border-gray-100 shadow-sm p-6 md:p-8">
              <div className="flex items-start gap-4 mb-6">
                <span className="bg-gray-100 text-gray-500 font-bold w-10 h-10 rounded-full flex items-center justify-center shrink-0">
                  {idx + 1}
                </span>
                <p className="text-lg font-medium text-gray-800 leading-relaxed pt-1">
                  {q.questionText}
                </p>
              </div>

              <div className="grid grid-cols-1 gap-3 ml-0 md:ml-14">
                {q.options.map((opt, optIdx) => {
                  const isUserSelection = selected === optIdx;
                  const isCorrectAnswer = optIdx === q.correctIndex;

                  let bgColor = "bg-white border-gray-200 hover:bg-gray-50";
                  let textColor = "text-gray-700";
                  let borderColor = "border-gray-200";

                  if (isFinished) {
                    if (isCorrectAnswer) {
                      bgColor = "bg-emerald-50 border-emerald-500 ring-1 ring-emerald-500";
                      textColor = "text-emerald-800";
                      borderColor = "border-emerald-500";
                    } else if (isUserSelection && !isCorrect) {
                      bgColor = "bg-rose-50 border-rose-500 ring-1 ring-rose-500";
                      textColor = "text-rose-800";
                      borderColor = "border-rose-500";
                    } else {
                      bgColor = "bg-white opacity-60 border-gray-200";
                    }
                  } else if (isUserSelection) {
                    bgColor = "bg-indigo-50 border-indigo-500 ring-1 ring-indigo-500";
                    textColor = "text-indigo-800";
                    borderColor = "border-indigo-500";
                  }

                  return (
                    <button
                      key={optIdx}
                      disabled={isFinished}
                      onClick={() => handleSelect(q.id, optIdx)}
                      className={`relative text-left p-4 rounded-xl border transition-all flex items-center gap-4 ${bgColor} ${textColor} ${borderColor}`}
                    >
                      <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center shrink-0 ${isUserSelection ? 'bg-indigo-600 border-indigo-600' : 'border-gray-300'}`}>
                        {isUserSelection && <div className="w-2 h-2 bg-white rounded-full"></div>}
                      </div>
                      <span className="flex-grow">{opt}</span>

                      {isFinished && isCorrectAnswer && (
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-emerald-600" viewBox="0 0 20 20" fill="currentColor">
                          <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                        </svg>
                      )}
                      {isFinished && isUserSelection && !isCorrect && (
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-rose-600" viewBox="0 0 20 20" fill="currentColor">
                          <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
                        </svg>
                      )}
                    </button>
                  );
                })}
              </div>

              {isFinished && (
                <div className="mt-6 ml-0 md:ml-14 bg-indigo-50/50 p-5 rounded-xl border border-indigo-100">
                  <div className="flex items-center gap-2 mb-2 text-indigo-700 font-bold">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                      <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
                    </svg>
                    Retroalimentación
                  </div>
                  <p className="text-indigo-800 mb-2">
                    <span className="font-bold">Respuesta correcta: </span> 
                    {q.options[q.correctIndex]}
                  </p>
                  <p className="text-gray-600 text-sm italic leading-relaxed">
                    {q.explanation}
                  </p>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

