import React, { useState, useMemo } from 'react';
import { Question } from '../types';
import { ACADEMIC_STRUCTURE } from '../constants';

interface AdminViewProps {
  questions: Question[];
  onSaveBatch: (questions: Question[]) => void;
  onUpdateQuestion: (question: Question) => void;
  onDeleteQuestion: (id: string) => void;
}

const AdminView: React.FC<AdminViewProps> = ({ questions, onSaveBatch, onUpdateQuestion, onDeleteQuestion }) => {
  const [activeTab, setActiveTab] = useState<'EDITOR' | 'MANAGE'>('EDITOR');
  const [currentBatch, setCurrentBatch] = useState<Question[]>([]);

  // Form State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [course, setCourse] = useState('');
  const [subject, setSubject] = useState('');
  const [topic, setTopic] = useState('');
  const [questionText, setQuestionText] = useState('');
  const [options, setOptions] = useState<string[]>(['', '', '', '', '']);
  const [correctIndex, setCorrectIndex] = useState(0);
  const [explanation, setExplanation] = useState('');

  const isBatchStarted = currentBatch.length > 0;
  const isEditing = !!editingId;

  const currentCourse = ACADEMIC_STRUCTURE.find(c => c.name === course);
  const availableSubjects = currentCourse?.subjects || [];

  const resetForm = (full: boolean = true) => {
    setQuestionText('');
    setOptions(['', '', '', '', '']);
    setCorrectIndex(0);
    setExplanation('');
    setEditingId(null);
    if (full) {
      setCourse('');
      setSubject('');
      setTopic('');
    }
  };

  const handleAddOrUpdate = () => {
    if (!course || !subject || !topic || !questionText || options.some(o => !o) || !explanation) {
      alert("Por favor completa todos los campos.");
      return;
    }

    if (isEditing) {
      const updatedQ: Question = {
        id: editingId!,
        course,
        subject,
        topic,
        questionText,
        options: [...options],
        correctIndex,
        explanation,
        order: questions.find(q => q.id === editingId)?.order ?? 999,
        createdAt: questions.find(q => q.id === editingId)?.createdAt ?? Date.now()
      };
      onUpdateQuestion(updatedQ);
      alert("Pregunta actualizada con éxito.");
      resetForm();
      setActiveTab('MANAGE');
    } else {
      const newQ: Question = {
        id: crypto.randomUUID(),
        course,
        subject,
        topic,
        questionText,
        options: [...options],
        correctIndex,
        explanation,
        order: 999,
        createdAt: Date.now()
      };
      setCurrentBatch(prev => [...prev, newQ]);
      resetForm(false); // keep course/subject/topic for batch speed
    }
  };

  const handleEditExisting = (q: Question) => {
    setEditingId(q.id);
    setCourse(q.course);
    setSubject(q.subject);
    setTopic(q.topic);
    setQuestionText(q.questionText);
    setOptions([...q.options]);
    setCorrectIndex(q.correctIndex);
    setExplanation(q.explanation);
    setActiveTab('EDITOR');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleDeleteExisting = (id: string) => {
    if (window.confirm("¿Estás seguro de que deseas eliminar esta pregunta del banco?")) {
      onDeleteQuestion(id);
    }
  };

  const handleSaveAllBatch = () => {
    if (currentBatch.length === 0) return;
    onSaveBatch(currentBatch);
    setCurrentBatch([]);
    resetForm();
    alert("Práctica guardada correctamente.");
  };

  const handleOptionChange = (idx: number, val: string) => {
    const newOpts = [...options];
    newOpts[idx] = val;
    setOptions(newOpts);
  };

  // Filter for management tab
  const [manageFilterCourse, setManageFilterCourse] = useState('');
  const [manageFilterSubject, setManageFilterSubject] = useState('');

  const filteredQuestions = useMemo(() => {
    return questions.filter(q => {
      const matchCourse = !manageFilterCourse || q.course === manageFilterCourse;
      const matchSubject = !manageFilterSubject || q.subject === manageFilterSubject;
      return matchCourse && matchSubject;
    });
  }, [questions, manageFilterCourse, manageFilterSubject]);

  return (
    <div className="max-w-7xl mx-auto">
      {/* Tab Switcher */}
      <div className="flex bg-gray-100 p-1.5 rounded-2xl w-fit mb-8 mx-auto border border-gray-200 shadow-inner">
        <button 
          onClick={() => { setActiveTab('EDITOR'); if(!isEditing) resetForm(); }}
          className={`px-8 py-2.5 rounded-xl font-bold text-sm transition-all ${activeTab === 'EDITOR' ? 'bg-white text-indigo-700 shadow-md' : 'text-gray-500 hover:text-gray-700'}`}
        >
          {isEditing ? 'Editando Pregunta' : 'Añadir Nuevas'}
        </button>
        <button 
          onClick={() => setActiveTab('MANAGE')}
          className={`px-8 py-2.5 rounded-xl font-bold text-sm transition-all ${activeTab === 'MANAGE' ? 'bg-white text-indigo-700 shadow-md' : 'text-gray-500 hover:text-gray-700'}`}
        >
          Gestionar Banco ({questions.length})
        </button>
      </div>

      {activeTab === 'EDITOR' ? (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          {/* Editor Form */}
          <div className="lg:col-span-7 space-y-6">
            <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6 md:p-8">
              <h2 className="text-2xl font-black text-gray-800 mb-6 flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <span className="bg-indigo-600 text-white p-2 rounded-lg">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                    </svg>
                  </span>
                  {isEditing ? 'Editando Pregunta' : 'Editor de Preguntas'}
                </div>
                {isEditing && (
                  <button 
                    onClick={() => resetForm()}
                    className="text-xs font-bold text-gray-400 hover:text-rose-500 uppercase tracking-widest transition-colors"
                  >
                    Cancelar Edición
                  </button>
                )}
              </h2>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
                <div>
                  <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2">Curso</label>
                  <select 
                    value={course} 
                    onChange={(e) => setCourse(e.target.value)}
                    disabled={isBatchStarted}
                    className="w-full bg-gray-50 border border-gray-200 rounded-xl p-3 focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                  >
                    <option value="">Selecciona curso...</option>
                    {ACADEMIC_STRUCTURE.map(c => <option key={c.name} value={c.name}>{c.name}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2">Materia</label>
                  <select 
                    value={subject} 
                    onChange={(e) => setSubject(e.target.value)}
                    disabled={isBatchStarted || !course}
                    className="w-full bg-gray-50 border border-gray-200 rounded-xl p-3 focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                  >
                    <option value="">Selecciona materia...</option>
                    {availableSubjects.map(s => <option key={s} value={s}>{s}</option>)}
                  </select>
                </div>
                <div className="md:col-span-2">
                  <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2">Nombre del Tema / Práctica</label>
                  <input 
                    type="text" 
                    value={topic} 
                    onChange={(e) => setTopic(e.target.value)}
                    disabled={isBatchStarted}
                    placeholder="Ej. Ecuaciones de Segundo Grado"
                    className="w-full bg-gray-50 border border-gray-200 rounded-xl p-3 focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                  />
                </div>
              </div>

              <hr className="my-8 border-gray-100" />

              <div className="space-y-6">
                <div>
                  <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2">Enunciado de la Pregunta</label>
                  <textarea 
                    value={questionText}
                    onChange={(e) => setQuestionText(e.target.value)}
                    className="w-full bg-gray-50 border border-gray-200 rounded-xl p-4 min-h-[100px] focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                    placeholder="Escribe la pregunta aquí..."
                  />
                </div>

                <div className="space-y-3">
                  <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-1">Alternativas (Marcar la correcta)</label>
                  {options.map((opt, idx) => (
                    <div key={idx} className="flex gap-3 items-center">
                      <input 
                        type="radio" 
                        name="correct" 
                        checked={correctIndex === idx} 
                        onChange={() => setCorrectIndex(idx)}
                        className="w-5 h-5 accent-indigo-600"
                      />
                      <input 
                        type="text" 
                        value={opt}
                        onChange={(e) => handleOptionChange(idx, e.target.value)}
                        placeholder={`Alternativa ${String.fromCharCode(65 + idx)}`}
                        className="flex-grow bg-gray-50 border border-gray-200 rounded-xl p-3 focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                      />
                    </div>
                  ))}
                </div>

                <div>
                  <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2">Explicación de la Respuesta</label>
                  <textarea 
                    value={explanation}
                    onChange={(e) => setExplanation(e.target.value)}
                    className="w-full bg-gray-50 border border-gray-200 rounded-xl p-4 min-h-[80px] focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                    placeholder="¿Por qué esta es la respuesta correcta?"
                  />
                </div>

                <button 
                  onClick={handleAddOrUpdate}
                  className={`w-full py-4 rounded-xl font-bold active:scale-[0.98] transition-all flex items-center justify-center gap-2 ${isEditing ? 'bg-indigo-600 hover:bg-indigo-700 text-white shadow-lg' : 'bg-gray-800 text-white hover:bg-gray-900'}`}
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M10 3a1 1 0 011 1v5h5a1 1 0 110 2h-5v5a1 1 0 11-2 0v-5H4a1 1 0 110-2h5V4a1 1 0 011-1z" clipRule="evenodd" />
                  </svg>
                  {isEditing ? 'Actualizar Pregunta' : 'Añadir a la lista temporal'}
                </button>
              </div>
            </div>
          </div>

          {/* Batch Preview */}
          <div className="lg:col-span-5 space-y-6">
            <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6 md:p-8 sticky top-[100px]">
              <div className="flex items-center justify-between mb-6">
                <h3 className="text-xl font-bold text-gray-800 flex items-center gap-2">
                  Cola de Nuevas: 
                  <span className="bg-indigo-100 text-indigo-700 px-3 py-1 rounded-full text-sm">
                    {currentBatch.length}
                  </span>
                </h3>
                {isBatchStarted && (
                  <button 
                    onClick={handleSaveAllBatch}
                    className="bg-emerald-600 text-white px-5 py-2.5 rounded-lg text-sm font-bold hover:bg-emerald-700 transition-all shadow-md shadow-emerald-100 active:scale-95"
                  >
                    Guardar Todo
                  </button>
                )}
              </div>

              {currentBatch.length === 0 ? (
                <div className="text-center py-12 px-6 border-2 border-dashed border-gray-100 rounded-xl">
                  <p className="text-gray-400 italic">No hay preguntas en cola.</p>
                </div>
              ) : (
                <div className="max-h-[60vh] overflow-y-auto space-y-3 pr-2 scrollbar-thin">
                  {currentBatch.map((q, idx) => (
                    <div key={q.id} className="p-4 bg-gray-50 border border-gray-100 rounded-xl">
                      <div className="flex justify-between items-start gap-3">
                        <span className="text-indigo-600 font-bold text-xs uppercase">Pregunta {idx + 1}</span>
                        <button 
                          onClick={() => setCurrentBatch(prev => prev.filter(item => item.id !== q.id))}
                          className="text-gray-300 hover:text-rose-500 transition-colors"
                        >
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                            <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l1.293 1.293a1 1 0 01-1.414 1.414L10 11.414l-1.293 1.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                          </svg>
                        </button>
                      </div>
                      <p className="text-gray-700 text-sm font-medium line-clamp-2 mt-1">{q.questionText}</p>
                      <div className="mt-2 text-[10px] text-gray-400 uppercase font-black tracking-tighter">
                        Correcta: {String.fromCharCode(65 + q.correctIndex)}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      ) : (
        /* Management Tab */
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6 md:p-8">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8 border-b pb-6">
            <h2 className="text-2xl font-black text-gray-800">Gestionar Banco de Preguntas</h2>
            <div className="flex flex-wrap gap-3">
              <select 
                value={manageFilterCourse} 
                onChange={(e) => { setManageFilterCourse(e.target.value); setManageFilterSubject(''); }}
                className="bg-gray-50 border border-gray-200 rounded-xl px-4 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                <option value="">Todos los Cursos</option>
                {ACADEMIC_STRUCTURE.map(c => <option key={c.name} value={c.name}>{c.name}</option>)}
              </select>
              <select 
                value={manageFilterSubject} 
                onChange={(e) => setManageFilterSubject(e.target.value)}
                disabled={!manageFilterCourse}
                className="bg-gray-50 border border-gray-200 rounded-xl px-4 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                <option value="">Todas las Materias</option>
                {ACADEMIC_STRUCTURE.find(c => c.name === manageFilterCourse)?.subjects.map(s => (
                  <option key={s} value={s}>{s}</option>
                ))}
              </select>
            </div>
          </div>

          {filteredQuestions.length === 0 ? (
            <div className="text-center py-20 bg-gray-50 rounded-2xl border-2 border-dashed border-gray-200">
              <div className="text-4xl mb-4">🔎</div>
              <p className="text-gray-500">No se encontraron preguntas con los filtros aplicados.</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {filteredQuestions.map((q) => (
                <div key={q.id} className="bg-white border border-gray-100 rounded-xl p-5 hover:shadow-md transition-all group flex flex-col">
                  <div className="flex justify-between items-start mb-3">
                    <span className="bg-indigo-50 text-indigo-600 text-[10px] font-black px-2 py-0.5 rounded uppercase tracking-widest">
                      {q.subject}
                    </span>
                    <div className="flex gap-2">
                      <button 
                        onClick={() => handleEditExisting(q)}
                        className="p-2 text-indigo-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                        title="Editar Pregunta"
                      >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                        </svg>
                      </button>
                      <button 
                        onClick={() => handleDeleteExisting(q.id)}
                        className="p-2 text-gray-300 hover:text-rose-500 hover:bg-rose-50 rounded-lg transition-all"
                        title="Eliminar Pregunta"
                      >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                        </svg>
                      </button>
                    </div>
                  </div>
                  <p className="text-gray-800 text-sm font-medium mb-4 line-clamp-3 flex-grow">{q.questionText}</p>
                  <div className="text-[10px] text-gray-400 mt-auto pt-3 border-t border-gray-50 flex justify-between">
                    <span>Tema: {q.topic}</span>
                    <span className="font-bold text-indigo-300">Respuesta: {String.fromCharCode(65 + q.correctIndex)}</span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default AdminView;

import React, { useMemo } from 'react';
import { Question } from '../types';

interface TopicsViewProps {
  subjectName: string;
  questions: Question[];
  onSelectTopic: (topic: string) => void;
  onDeleteTopic: (topic: string) => void;
  onMoveTopic: (topic: string, direction: 'UP' | 'DOWN') => void;
}

const TopicsView: React.FC<TopicsViewProps> = ({ 
  subjectName, 
  questions, 
  onSelectTopic, 
  onDeleteTopic, 
  onMoveTopic 
}) => {
  const topics = useMemo(() => {
    const grouped = questions.reduce((acc, q) => {
      if (!acc[q.topic]) {
        acc[q.topic] = {
          name: q.topic,
          count: 0,
          order: q.order ?? 999
        };
      }
      acc[q.topic].count++;
      return acc;
    }, {} as Record<string, { name: string, count: number, order: number }>);

    // Explicitly cast the result of Object.values to the expected item type array to resolve 'unknown' type issues in older TS environments
    return (Object.values(grouped) as { name: string; count: number; order: number }[])
      .sort((a, b) => a.order - b.order);
  }, [questions]);

  return (
    <div>
      <div className="flex justify-between items-end mb-8 border-b pb-4">
        <div>
          <p className="text-indigo-600 font-bold uppercase tracking-widest text-xs mb-1">Materia</p>
          <h2 className="text-3xl font-bold text-gray-800">{subjectName}</h2>
        </div>
        <div className="text-right text-gray-400 text-sm">
          {topics.length} temas registrados
        </div>
      </div>

      {topics.length === 0 ? (
        <div className="bg-gray-50 rounded-2xl border-2 border-dashed border-gray-200 p-12 text-center">
          <div className="text-5xl mb-4">📭</div>
          <h3 className="text-lg font-medium text-gray-600">No hay temas registrados aún</h3>
          <p className="text-gray-400 mt-2">Ve al Panel de Admin para crear la primera práctica.</p>
        </div>
      ) : (
        <div className="space-y-4">
          {topics.map((topic, index) => (
            <div 
              key={topic.name}
              className="bg-white rounded-xl shadow-sm border border-gray-100 p-5 flex flex-col md:flex-row items-center gap-6 hover:border-indigo-200 transition-colors"
            >
              <div className="bg-indigo-50 text-indigo-700 w-12 h-12 rounded-lg flex items-center justify-center font-black text-lg shrink-0">
                {topic.order === 999 ? '?' : topic.order}
              </div>

              <div className="flex-grow text-center md:text-left">
                <h4 className="text-xl font-bold text-gray-800">{topic.name}</h4>
                <p className="text-gray-400 text-sm">{topic.count} preguntas en este banco</p>
              </div>

              <div className="flex flex-wrap items-center justify-center gap-2 shrink-0">
                <div className="flex border rounded-lg overflow-hidden bg-gray-50">
                  <button 
                    onClick={() => onMoveTopic(topic.name, 'UP')}
                    disabled={index === 0}
                    className="p-2 hover:bg-gray-200 disabled:opacity-30 disabled:hover:bg-gray-50 transition-colors"
                    title="Mover Arriba"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                      <path fillRule="evenodd" d="M14.707 12.707a1 1 0 01-1.414 0L10 9.414l-3.293 3.293a1 1 0 01-1.414-1.414l4-4a1 1 0 011.414 0l4 4a1 1 0 010 1.414z" clipRule="evenodd" />
                    </svg>
                  </button>
                  <button 
                    onClick={() => onMoveTopic(topic.name, 'DOWN')}
                    disabled={index === topics.length - 1}
                    className="p-2 border-l hover:bg-gray-200 disabled:opacity-30 disabled:hover:bg-gray-50 transition-colors"
                    title="Mover Abajo"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                      <path fillRule="evenodd" d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z" clipRule="evenodd" />
                    </svg>
                  </button>
                </div>

                <button 
                  onClick={() => onSelectTopic(topic.name)}
                  className="bg-indigo-600 text-white px-5 py-2.5 rounded-lg text-sm font-bold hover:bg-indigo-700 active:scale-95 transition-all shadow-sm flex items-center gap-2"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
                  </svg>
                  Iniciar Quiz
                </button>

                <button 
                  onClick={() => onDeleteTopic(topic.name)}
                  className="p-2.5 text-rose-500 hover:bg-rose-50 rounded-lg transition-colors"
                  title="Eliminar Práctica"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                  </svg>
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

