                    <p className="text-gray-600 italic leading-relaxed bg-white/50 p-4 rounded-xl border border-indigo-50">
                      {q.explanation}
                    </p>
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

