import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Question, AppDatabase, ViewType, NavigationState } from './types';
import { ACADEMIC_STRUCTURE, DB_STORAGE_KEY } from './constants';
import Navbar from './components/Navbar';
import HomeView from './views/HomeView';
import SubjectsView from './views/SubjectsView';
import TopicsView from './views/TopicsView';
import QuizView from './views/QuizView';
import AdminView from './views/AdminView';
import MegaQuizView from './views/MegaQuizView';

const App: React.FC = () => {
  const [db, setDb] = useState<AppDatabase>(() => {
    const saved = localStorage.getItem(DB_STORAGE_KEY);
    return saved ? JSON.parse(saved) : { questions: [] };
  });

  const [nav, setNav] = useState<NavigationState>({
    view: 'HOME'
  });

  const [isDark, setIsDark] = useState(() => {
    const saved = localStorage.getItem('theme');
    return saved ? saved === 'dark' : true;
  });

  useEffect(() => {
    if (isDark) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDark]);

  // Sync with Local Storage
  useEffect(() => {
    localStorage.setItem(DB_STORAGE_KEY, JSON.stringify(db));
  }, [db]);

  const handleNavigate = useCallback((view: ViewType, params?: Partial<NavigationState>) => {
    setNav(prev => ({ ...prev, view, ...params }));
  }, []);

  const handleBack = useCallback(() => {
    setNav(prev => {
      if (prev.view === 'ADMIN' || prev.view === 'MEGA_QUIZ') return { ...prev, view: 'HOME' };
      if (prev.view === 'QUIZ') return { ...prev, view: 'TOPICS' };
      if (prev.view === 'TOPICS') return { ...prev, view: 'SUBJECTS', selectedTopic: undefined };
      if (prev.view === 'SUBJECTS') return { ...prev, view: 'HOME', selectedSubject: undefined };
      return prev;
    });
  }, []);

  const handleImport = useCallback((data: AppDatabase) => {
    setDb(data);
    alert('Base de datos importada con éxito.');
  }, []);

  const handleExport = useCallback(() => {
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(db, null, 2));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", `educasani_backup_${new Date().toISOString().split('T')[0]}.json`);
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  }, [db]);

  const saveQuestions = useCallback((newQuestions: Question[]) => {
    setDb(prev => ({
      ...prev,
      questions: [...prev.questions, ...newQuestions]
    }));
  }, []);

  const updateQuestion = useCallback((updatedQ: Question) => {
    setDb(prev => ({
      ...prev,
      questions: prev.questions.map(q => q.id === updatedQ.id ? updatedQ : q)
    }));
  }, []);

  const deleteQuestion = useCallback((id: string) => {
    setDb(prev => ({
      ...prev,
      questions: prev.questions.filter(q => q.id !== id)
    }));
  }, []);

  const deleteTopic = useCallback((topicName: string, subjectName: string) => {
    if (window.confirm(`¿Seguro que deseas eliminar la práctica "${topicName}"?`)) {
      setDb(prev => ({
        ...prev,
        questions: prev.questions.filter(q => !(q.topic === topicName && q.subject === subjectName))
      }));
    }
  }, []);

  const moveTopic = useCallback((topicName: string, subjectName: string, direction: 'UP' | 'DOWN') => {
    setDb(prev => {
      const subjectQuestions = prev.questions.filter(q => q.subject === subjectName);
      const otherQuestions = prev.questions.filter(q => q.subject !== subjectName);

      const uniqueTopics = Array.from(new Set(subjectQuestions.map(q => q.topic)))
        .map(t => ({
          name: t,
          order: subjectQuestions.find(q => q.topic === t)?.order ?? 999
        }))
        .sort((a, b) => a.order - b.order);

      const currentIndex = uniqueTopics.findIndex(t => t.name === topicName);
      if (currentIndex === -1) return prev;

      const targetIndex = direction === 'UP' ? currentIndex - 1 : currentIndex + 1;
      if (targetIndex < 0 || targetIndex >= uniqueTopics.length) return prev;

      const currentTopic = uniqueTopics[currentIndex];
      const targetTopic = uniqueTopics[targetIndex];
      const currentOrder = currentTopic.order;
      const targetOrder = targetTopic.order;

      const updatedSubjectQuestions = subjectQuestions.map(q => {
        if (q.topic === currentTopic.name) return { ...q, order: targetOrder };
        if (q.topic === targetTopic.name) return { ...q, order: currentOrder };
        return q;
      });

      return {
        ...prev,
        questions: [...otherQuestions, ...updatedSubjectQuestions]
      };
    });
  }, []);

  const renderView = () => {
    switch (nav.view) {
      case 'HOME':
        return (
          <HomeView 
            onSelectCourse={(course) => handleNavigate('SUBJECTS', { selectedCourse: course })} 
            onStartMegaQuiz={() => handleNavigate('MEGA_QUIZ')}
          />
        );
      case 'SUBJECTS':
        return (
          <SubjectsView 
            courseName={nav.selectedCourse!} 
            onSelectSubject={(subject) => handleNavigate('TOPICS', { selectedSubject: subject })} 
          />
        );
      case 'TOPICS':
        return (
          <TopicsView 
            subjectName={nav.selectedSubject!} 
            questions={db.questions.filter(q => q.subject === nav.selectedSubject)}
            onSelectTopic={(topic) => handleNavigate('QUIZ', { selectedTopic: topic })}
            onDeleteTopic={(topic) => deleteTopic(topic, nav.selectedSubject!)}
            onMoveTopic={(topic, dir) => moveTopic(topic, nav.selectedSubject!, dir)}
          />
        );
      case 'QUIZ':
        return (
          <QuizView 
            topicName={nav.selectedTopic!}
            questions={db.questions.filter(q => q.topic === nav.selectedTopic && q.subject === nav.selectedSubject)}
          />
        );
      case 'MEGA_QUIZ':
        return (
          <MegaQuizView 
            questions={db.questions}
          />
        );
      case 'ADMIN':
        return (
          <AdminView 
            questions={db.questions}
            onSaveBatch={saveQuestions}
            onUpdateQuestion={updateQuestion}
            onDeleteQuestion={deleteQuestion}
          />
        );
      default:
        return <HomeView onSelectCourse={(course) => handleNavigate('SUBJECTS', { selectedCourse: course })} onStartMegaQuiz={() => handleNavigate('MEGA_QUIZ')} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-gray-50 dark:bg-slate-950 transition-colors duration-300">
      <Navbar 
        onNavigate={handleNavigate} 
        onBack={handleBack} 
        onImport={handleImport} 
        onExport={handleExport}
        currentView={nav.view}
        navState={nav}
        isDark={isDark}
        toggleTheme={() => setIsDark(!isDark)}
      />
      <main className="flex-grow container mx-auto px-4 py-8">
        {renderView()}
      </main>
      <footer className="bg-white dark:bg-slate-900 dark:border-slate-800 border-t py-6 text-center text-sm text-gray-500 dark:text-gray-400">
        &copy; {new Date().getFullYear()} EduCasani • Sistema de Gestión Académica
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import { ViewType, NavigationState, AppDatabase } from '../types';

interface NavbarProps {
  onNavigate: (view: ViewType, params?: Partial<NavigationState>) => void;
  onBack: () => void;
  onImport: (data: AppDatabase) => void;
  onExport: () => void;
  currentView: ViewType;
  navState: NavigationState;
  isDark: boolean;
  toggleTheme: () => void;
}

const Navbar: React.FC<NavbarProps> = ({ onNavigate, onBack, onImport, onExport, currentView, navState, isDark, toggleTheme }) => {
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        onImport(json);
      } catch (err) {
        alert("Error al procesar el archivo JSON.");
      }
    };
    reader.readAsText(file);
  };

  return (
    <nav className="bg-indigo-700 dark:bg-indigo-900 text-white shadow-lg sticky top-0 z-50">
      <div className="container mx-auto px-4 py-3 flex flex-wrap items-center justify-between gap-4">
        <div className="flex items-center gap-3">
          {currentView !== 'HOME' && (
            <button 
              onClick={onBack}
              className="p-2 hover:bg-indigo-600 dark:hover:bg-indigo-800 rounded-full transition-colors"
              title="Volver"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
              </svg>
            </button>
          )}
          <div 
            className="cursor-pointer" 
            onClick={() => onNavigate('HOME')}
          >
            <h1 className="text-xl font-bold tracking-tight">EduCasani <span className="font-light text-indigo-200">Cloud</span></h1>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <button
            onClick={toggleTheme}
            className="p-2 bg-indigo-800 dark:bg-indigo-950 hover:bg-indigo-600 rounded-lg transition-colors mr-2"
            title={isDark ? "Cambiar a Modo Claro" : "Cambiar a Modo Oscuro"}
          >
            {isDark ? (
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364-6.364l-.707.707M6.343 17.657l-.707.707M16.95 16.95l.707.707M7.05 7.05l.707.707M16 12a4 4 0 11-8 0 4 4 0 018 0z" />
              </svg>
            ) : (
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z" />
              </svg>
            )}
          </button>
          <label className="cursor-pointer bg-indigo-800 dark:bg-indigo-950 hover:bg-indigo-600 dark:hover:bg-indigo-800 px-4 py-2 rounded-lg text-sm font-medium transition-colors flex items-center gap-2">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
            </svg>
            <span className="hidden sm:inline">Importar</span>
            <input type="file" className="hidden" accept=".json" onChange={handleFileChange} />
          </label>
          <button 
            onClick={onExport}
            className="bg-indigo-800 dark:bg-indigo-950 hover:bg-indigo-600 dark:hover:bg-indigo-800 px-4 py-2 rounded-lg text-sm font-medium transition-colors flex items-center gap-2"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
            </svg>
            <span className="hidden sm:inline">Exportar</span>
          </button>
          <button 
            onClick={() => onNavigate('ADMIN')}
            className="bg-white text-indigo-700 hover:bg-gray-100 dark:bg-indigo-100 dark:hover:bg-white px-4 py-2 rounded-lg text-sm font-bold transition-colors ml-2"
          >
            Panel Admin
          </button>
        </div>
      </div>

      {/* Breadcrumbs / Subtitle */}
      <div className="bg-indigo-800/50 dark:bg-indigo-950/50 py-1.5 px-4 text-xs font-medium text-indigo-100 border-t border-indigo-600/30 dark:border-indigo-800/30">
        <div className="container mx-auto">
          {currentView === 'HOME' && "Inicio / Cursos"}
          {currentView === 'SUBJECTS' && `Cursos / ${navState.selectedCourse}`}
          {currentView === 'TOPICS' && `Cursos / ${navState.selectedCourse} / ${navState.selectedSubject}`}
          {currentView === 'QUIZ' && `Cursos / ${navState.selectedCourse} / ${navState.selectedSubject} / ${navState.selectedTopic}`}
          {currentView === 'ADMIN' && "Administración / Editor de Preguntas"}
        </div>
      </div>
    </nav>
  );
};

