import React, { useState } from 'react';
import { Question } from '../types';

interface QuizViewProps {
  topicName: string;
  questions: Question[];
}

const QuizView: React.FC<QuizViewProps> = ({ topicName, questions }) => {
  const [answers, setAnswers] = useState<Record<string, number>>({});
  const [isFinished, setIsFinished] = useState(false);

  const handleSelect = (qId: string, optIndex: number) => {
    if (isFinished) return;
    setAnswers(prev => ({ ...prev, [qId]: optIndex }));
  };

  const calculateScore = () => {
    let score = 0;
    questions.forEach(q => {
      if (answers[q.id] === q.correctIndex) score++;
    });
    return score;
  };

  const score = calculateScore();

  return (
    <div className="max-w-4xl mx-auto">
      <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-gray-100 dark:border-slate-800 p-6 mb-8 sticky top-[80px] z-40 flex flex-col md:flex-row items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-black text-gray-800 dark:text-gray-100">{topicName}</h2>
          <p className="text-gray-400 dark:text-gray-500 text-sm">Contesta todas las preguntas para ver tus resultados.</p>
        </div>
        {!isFinished ? (
          <button 
            onClick={() => setIsFinished(true)}
            className="w-full md:w-auto bg-indigo-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-indigo-700 shadow-md active:scale-95 transition-all"
          >
            Calificar Simulacro
          </button>
        ) : (
          <div className="text-center px-6 py-2 bg-indigo-50 dark:bg-indigo-900/30 border border-indigo-200 dark:border-indigo-800 rounded-xl">
            <span className="text-xs uppercase font-black text-indigo-400 dark:text-indigo-300 block tracking-widest">Puntaje Final</span>
            <span className="text-3xl font-black text-indigo-700 dark:text-indigo-200">{score} / {questions.length}</span>
          </div>
        )}
      </div>

      <div className="space-y-8 pb-12">
        {questions.map((q, idx) => {
          const selected = answers[q.id];
          const isCorrect = selected === q.correctIndex;

          return (
            <div key={q.id} className="bg-white dark:bg-slate-900 rounded-2xl border border-gray-100 dark:border-slate-800 shadow-sm p-6 md:p-8">
              <div className="flex items-start gap-4 mb-6">
                <span className="bg-gray-100 dark:bg-slate-800 text-gray-500 dark:text-gray-400 font-bold w-10 h-10 rounded-full flex items-center justify-center shrink-0">
                  {idx + 1}
                </span>
                <p className="text-lg font-medium text-gray-800 dark:text-gray-200 leading-relaxed pt-1">
                  {q.questionText}
                </p>
              </div>

              <div className="grid grid-cols-1 gap-3 ml-0 md:ml-14">
                {q.options.map((opt, optIdx) => {
                  const isUserSelection = selected === optIdx;
                  const isCorrectAnswer = optIdx === q.correctIndex;

                  let bgColor = "bg-white dark:bg-slate-800 border-gray-200 dark:border-slate-700 hover:bg-gray-50 dark:hover:bg-slate-700/50";
                  let textColor = "text-gray-700 dark:text-gray-300";
                  let borderColor = "border-gray-200 dark:border-slate-700";

                  if (isFinished) {
                    if (isCorrectAnswer) {
                      bgColor = "bg-emerald-50 dark:bg-emerald-900/30 border-emerald-500 dark:border-emerald-500 ring-1 ring-emerald-500";
                      textColor = "text-emerald-800 dark:text-emerald-200";
                      borderColor = "border-emerald-500";
                    } else if (isUserSelection && !isCorrect) {
                      bgColor = "bg-rose-50 dark:bg-rose-900/30 border-rose-500 dark:border-rose-500 ring-1 ring-rose-500";
                      textColor = "text-rose-800 dark:text-rose-200";
                      borderColor = "border-rose-500";
                    } else {
                      bgColor = "bg-white dark:bg-slate-900 opacity-60 border-gray-200 dark:border-slate-800";
                    }
                  } else if (isUserSelection) {
                    bgColor = "bg-indigo-50 dark:bg-indigo-900/30 border-indigo-500 dark:border-indigo-500 ring-1 ring-indigo-500";
                    textColor = "text-indigo-800 dark:text-indigo-200";
                    borderColor = "border-indigo-500";
                  }

                  return (
                    <button
                      key={optIdx}
                      disabled={isFinished}
                      onClick={() => handleSelect(q.id, optIdx)}
                      className={`relative text-left p-4 rounded-xl border transition-all flex items-center gap-4 ${bgColor} ${textColor} ${borderColor}`}
                    >
                      <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center shrink-0 ${isUserSelection ? 'bg-indigo-600 border-indigo-600' : 'border-gray-300 dark:border-slate-600'}`}>
                        {isUserSelection && <div className="w-2 h-2 bg-white rounded-full"></div>}
                      </div>
                      <span className="flex-grow">{opt}</span>

                      {isFinished && isCorrectAnswer && (
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-emerald-600 dark:text-emerald-400" viewBox="0 0 20 20" fill="currentColor">
                          <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                        </svg>
                      )}
                      {isFinished && isUserSelection && !isCorrect && (
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-rose-600 dark:text-rose-400" viewBox="0 0 20 20" fill="currentColor">
                          <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
                        </svg>
                      )}
                    </button>
                  );
                })}
              </div>

              {isFinished && (
                <div className="mt-6 ml-0 md:ml-14 bg-indigo-50/50 dark:bg-indigo-900/20 p-5 rounded-xl border border-indigo-100 dark:border-indigo-900/50">
                  <div className="flex items-center gap-2 mb-2 text-indigo-700 dark:text-indigo-300 font-bold">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                      <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
                    </svg>
                    Retroalimentación
                  </div>
                  <p className="text-indigo-800 dark:text-indigo-200 mb-2">
                    <span className="font-bold">Respuesta correcta: </span> 
                    {q.options[q.correctIndex]}
                  </p>
                  <p className="text-gray-600 dark:text-gray-400 text-sm italic leading-relaxed">
                    {q.explanation}
                  </p>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

