export default AdminView;

import React, { useState, useMemo, useEffect } from 'react';
import { Question } from '../types';
import { MEGA_EXAM_CONFIG } from '../constants';

interface MegaQuizViewProps {
  questions: Question[];
}

const MegaQuizView: React.FC<MegaQuizViewProps> = ({ questions }) => {
  const [answers, setAnswers] = useState<Record<string, number>>({});
  const [isFinished, setIsFinished] = useState(false);

  const INITIAL_TIME = 9000;
  const [timeLeft, setTimeLeft] = useState(INITIAL_TIME);

  useEffect(() => {
    if (isFinished) return;

    if (timeLeft <= 0) {
      setIsFinished(true);
      return;
    }

    const timer = setInterval(() => {
      setTimeLeft(prev => prev - 1);
    }, 1000);

    return () => clearInterval(timer);
  }, [timeLeft, isFinished]);

  const formatTime = (seconds: number) => {
    const hrs = Math.floor(seconds / 3600);
    const mins = Math.floor((seconds % 3600) / 60);
    const secs = seconds % 60;
    return `${hrs.toString().padStart(2, '0')}:${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const selectedQuestions = useMemo(() => {
    const finalSelection: { question: Question; weight: number; category: string }[] = [];

    Object.entries(MEGA_EXAM_CONFIG).forEach(([categoryName, config]) => {
      const pool = questions.filter(q => config.subjects.includes(q.subject));
      const shuffled = [...pool].sort(() => 0.5 - Math.random());
      const selected = shuffled.slice(0, config.count);

      selected.forEach(q => {
        finalSelection.push({
          question: q,
          weight: config.weight,
          category: categoryName
        });
      });
    });

    return finalSelection.sort(() => 0.5 - Math.random());
  }, [questions]);

  const handleSelect = (qId: string, optIndex: number) => {
    if (isFinished) return;
    setAnswers(prev => ({ ...prev, [qId]: optIndex }));
  };

  const calculateDetailedResults = () => {
    const breakdown: Record<string, { correct: number; total: number; points: number; maxPoints: number }> = {};
    let totalScore = 0;
    let totalCorrect = 0;

    selectedQuestions.forEach(item => {
      if (!breakdown[item.category]) {
        breakdown[item.category] = { correct: 0, total: 0, points: 0, maxPoints: 0 };
      }

      breakdown[item.category].total += 1;
      breakdown[item.category].maxPoints += item.weight;

      if (answers[item.question.id] === item.question.correctIndex) {
        breakdown[item.category].correct += 1;
        breakdown[item.category].points += item.weight;
        totalScore += item.weight;
        totalCorrect += 1;
      }
    });

    return { totalScore, totalCorrect, breakdown };
  };

  const results = useMemo(() => calculateDetailedResults(), [isFinished, answers, selectedQuestions]);

  if (selectedQuestions.length === 0) {
    return (
      <div className="max-w-2xl mx-auto py-20 text-center bg-white dark:bg-slate-900 rounded-3xl border border-gray-100 dark:border-slate-800 shadow-xl px-8">
        <div className="text-6xl mb-6">⚠️</div>
        <h2 className="text-2xl font-black text-gray-800 dark:text-gray-100 mb-4">Banco de preguntas insuficiente</h2>
        <p className="text-gray-500 dark:text-gray-400 mb-8 leading-relaxed">
          No hay preguntas registradas en el sistema para generar el simulacro. Por favor, añade preguntas en el panel de administración primero.
        </p>
      </div>
    );
  }

  return (
    <div className="max-w-5xl mx-auto">
      {/* Exam Header */}
      <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-xl border border-gray-100 dark:border-slate-800 p-8 mb-8 sticky top-[80px] z-40">
        <div className="flex flex-col md:flex-row items-center justify-between gap-6">
          <div className="flex-grow">
            <div className="flex items-center gap-3 mb-1">
              <span className="bg-indigo-600 text-white text-[10px] font-black px-2 py-0.5 rounded uppercase">Oficial</span>
              <h2 className="text-3xl font-black text-gray-800 dark:text-gray-100 tracking-tight">Simulacro General 80</h2>
            </div>
            <p className="text-gray-400 dark:text-gray-500 text-sm">Preguntas seleccionadas aleatoriamente con pesos ponderados.</p>
          </div>

          <div className="flex items-center gap-4">
            {!isFinished && (
              <div className={`flex flex-col items-center justify-center px-6 py-2 rounded-2xl border-2 transition-colors ${timeLeft < 300 ? 'bg-rose-50 dark:bg-rose-900/30 border-rose-200 dark:border-rose-800 animate-pulse' : 'bg-gray-50 dark:bg-slate-800 border-gray-200 dark:border-slate-700'}`}>
                <span className={`text-[10px] uppercase font-black block tracking-widest ${timeLeft < 300 ? 'text-rose-400 dark:text-rose-300' : 'text-gray-400 dark:text-gray-500'}`}>Tiempo</span>
                <span className={`text-2xl font-black font-mono ${timeLeft < 300 ? 'text-rose-600 dark:text-rose-400' : 'text-gray-700 dark:text-gray-200'}`}>
                  {formatTime(timeLeft)}
                </span>
              </div>
            )}

            {!isFinished ? (
              <button 
                onClick={() => {
                  if (Object.keys(answers).length < selectedQuestions.length) {
                    if (!window.confirm(`Has respondido ${Object.keys(answers).length} de ${selectedQuestions.length}. ¿Deseas calificar de todas formas?`)) return;
                  }
                  setIsFinished(true);
                  window.scrollTo({ top: 0, behavior: 'smooth' });
                }}
                className="bg-indigo-600 text-white px-10 py-4 rounded-2xl font-black hover:bg-indigo-700 shadow-xl shadow-indigo-100 dark:shadow-none active:scale-95 transition-all text-lg"
              >
                Finalizar
              </button>
            ) : (
              <div className="flex gap-4">
                 <div className="text-center px-8 py-3 bg-indigo-50 dark:bg-indigo-900/30 border-2 border-indigo-200 dark:border-indigo-800 rounded-2xl">
                    <span className="text-[10px] uppercase font-black text-indigo-400 dark:text-indigo-300 block tracking-widest">Puntaje Total</span>
                    <span className="text-4xl font-black text-indigo-700 dark:text-indigo-200">{results.totalScore.toFixed(4)} / 100.00</span>
                 </div>
              </div>
            )}
          </div>
        </div>
      </div>

      {isFinished && (
        <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-lg border border-gray-100 dark:border-slate-800 p-8 mb-10 overflow-hidden relative">
          <div className="absolute top-0 right-0 p-8 opacity-5">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-40 w-40" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </div>
          <h3 className="text-2xl font-black text-gray-800 dark:text-gray-100 mb-6 flex items-center gap-3">
            <span className="bg-emerald-100 dark:bg-emerald-900/50 text-emerald-600 dark:text-emerald-400 p-2 rounded-xl">📊</span>
            Reporte de Resultados por Materia
          </h3>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {(Object.entries(results.breakdown) as [string, { correct: number; total: number; points: number; maxPoints: number }][]).map(([cat, data]) => (
              <div key={cat} className="bg-gray-50 dark:bg-slate-800 border border-gray-100 dark:border-slate-700 rounded-2xl p-4 flex flex-col">
                <div className="flex justify-between items-start mb-2">
                  <span className="text-sm font-black text-gray-700 dark:text-gray-200">{cat}</span>
                  <span className={`text-[10px] font-bold px-2 py-0.5 rounded uppercase ${data.correct === data.total ? 'bg-emerald-100 dark:bg-emerald-900/50 text-emerald-600 dark:text-emerald-400' : 'bg-indigo-100 dark:bg-indigo-900/50 text-indigo-600 dark:text-indigo-400'}`}>
                    {data.correct}/{data.total} Q
                  </span>
                </div>
                <div className="mt-auto pt-2 flex justify-between items-baseline border-t border-gray-200/50 dark:border-slate-700">
                  <span className="text-[10px] text-gray-400 dark:text-gray-500 uppercase font-bold">Puntos Obtenidos:</span>
                  <span className="text-lg font-black text-indigo-600 dark:text-indigo-400">{data.points.toFixed(4)}</span>
                </div>
                <div className="text-[10px] text-right text-gray-300 dark:text-gray-600">Sobre {data.maxPoints.toFixed(4)} posibles</div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Question List */}
      <div className="space-y-10 pb-20">
        {selectedQuestions.map((item, idx) => {
          const q = item.question;
          const selected = answers[q.id];
          const isCorrect = selected === q.correctIndex;

          return (
            <div key={q.id} className={`bg-white dark:bg-slate-900 rounded-3xl border transition-all duration-300 ${isFinished ? (isCorrect ? 'border-emerald-200 dark:border-emerald-800 shadow-emerald-50 dark:shadow-none shadow-lg' : 'border-rose-200 dark:border-rose-800 shadow-rose-50 dark:shadow-none shadow-lg') : 'border-gray-100 dark:border-slate-800 shadow-sm'}`}>
              <div className="p-6 md:p-10">
                <div className="flex flex-wrap items-center justify-between gap-4 mb-6">
                  <div className="flex items-center gap-4">
                    <span className="bg-gray-800 dark:bg-slate-800 text-white font-black w-10 h-10 rounded-xl flex items-center justify-center shrink-0">
                      {idx + 1}
                    </span>
                    <div>
                      <span className="bg-indigo-50 dark:bg-indigo-900/50 text-indigo-600 dark:text-indigo-400 text-[10px] font-black px-2 py-0.5 rounded uppercase tracking-widest">
                        {item.category}
                      </span>
                      <span className="ml-2 text-gray-300 dark:text-gray-600 text-[10px] font-bold uppercase tracking-tighter">VALOR PREGUNTA: {item.weight.toFixed(8)}</span>
                    </div>
                  </div>
                </div>

                <p className="text-xl font-bold text-gray-800 dark:text-gray-100 leading-relaxed mb-8">
                  {q.questionText}
                </p>

                <div className="grid grid-cols-1 gap-3">
                  {q.options.map((opt, optIdx) => {
                    const isUserSelection = selected === optIdx;
                    const isCorrectAnswer = optIdx === q.correctIndex;

                    let bgColor = "bg-gray-50 dark:bg-slate-800 border-gray-100 dark:border-slate-700 hover:border-indigo-200 dark:hover:border-indigo-800";
                    let textColor = "text-gray-700 dark:text-gray-300";
                    let borderColor = "border-gray-200 dark:border-slate-700";

                    if (isFinished) {
                      if (isCorrectAnswer) {
                        bgColor = "bg-emerald-50 dark:bg-emerald-900/30 border-emerald-500 ring-2 ring-emerald-500";
                        textColor = "text-emerald-800 dark:text-emerald-200";
                        borderColor = "border-emerald-500";
                      } else if (isUserSelection && !isCorrect) {
                        bgColor = "bg-rose-50 dark:bg-rose-900/30 border-rose-500 ring-2 ring-rose-500";
                        textColor = "text-rose-800 dark:text-rose-200";
                        borderColor = "border-rose-500";
                      } else {
                        bgColor = "bg-white dark:bg-slate-900 opacity-40 border-gray-100 dark:border-slate-800";
                      }
                    } else if (isUserSelection) {
                      bgColor = "bg-indigo-50 dark:bg-indigo-900/50 border-indigo-500 ring-2 ring-indigo-500";
                      textColor = "text-indigo-800 dark:text-indigo-200";
                      borderColor = "border-indigo-500";
                    }

                    return (
                      <button
                        key={optIdx}
                        disabled={isFinished}
                        onClick={() => handleSelect(q.id, optIdx)}
                        className={`group relative text-left p-5 rounded-2xl border-2 transition-all flex items-center gap-4 ${bgColor} ${textColor} ${borderColor}`}
                      >
                        <div className={`w-8 h-8 rounded-xl border-2 flex items-center justify-center font-black transition-all shrink-0 ${isUserSelection ? 'bg-indigo-600 border-indigo-600 text-white' : 'border-gray-200 dark:border-slate-600 text-gray-400 group-hover:border-indigo-300 dark:group-hover:border-indigo-700'}`}>
                          {String.fromCharCode(65 + optIdx)}
                        </div>
                        <span className="flex-grow font-medium">{opt}</span>

                        {isFinished && isCorrectAnswer && (
                          <div className="bg-emerald-500 text-white p-1 rounded-full shrink-0">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                              <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                            </svg>
                          </div>
                        )}
                      </button>
                    );
                  })}
                </div>

                {isFinished && (
                  <div className="mt-10 bg-indigo-50/30 dark:bg-indigo-900/20 p-8 rounded-3xl border border-indigo-100 dark:border-indigo-800">
                    <div className="flex items-center gap-3 mb-4 text-indigo-700 dark:text-indigo-300 font-black uppercase text-sm tracking-widest">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
                      </svg>
                      Resolución Académica
                    </div>
                    <p className="text-indigo-900 dark:text-indigo-200 text-lg mb-4 font-bold">
                      Respuesta: {q.options[q.correctIndex]}
                    </p>
                    <p className="text-gray-600 dark:text-gray-400 italic leading-relaxed bg-white/50 dark:bg-slate-900/50 p-4 rounded-xl border border-indigo-50 dark:border-indigo-900/30">
                      {q.explanation}
                    </p>
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

