  questions: Question[];
  results?: Record<string, TopicResult>; // Clave: "Materia|Tema"
}

export type ViewType = 'HOME' | 'SUBJECTS' | 'TOPICS' | 'QUIZ' | 'ADMIN' | 'MEGA_QUIZ';

export interface NavigationState {
  view: ViewType;
  selectedCourse?: string;
  selectedSubject?: string;
  selectedTopic?: string;
}

