import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Question, AppDatabase, ViewType, NavigationState, TopicResult, ReadingText } from './types';
import { ACADEMIC_STRUCTURE, DB_STORAGE_KEY } from './constants';
import Navbar from './components/Navbar';
import HomeView from './views/HomeView';
import SubjectsView from './views/SubjectsView';
import TopicsView from './views/TopicsView';
import QuizView from './views/QuizView';
import AdminView from './views/AdminView';
import MegaQuizView from './views/MegaQuizView';

const App: React.FC = () => {
  const [db, setDb] = useState<AppDatabase>(() => {
    const saved = localStorage.getItem(DB_STORAGE_KEY);
    const initial = saved ? JSON.parse(saved) : { questions: [], readingTexts: [] };
    if (!initial.results) initial.results = {};
    if (!initial.readingTexts) initial.readingTexts = [];
    if (initial.totalPracticed === undefined) initial.totalPracticed = 0;
    return initial;
  });

  const [nav, setNav] = useState<NavigationState>({
    view: 'HOME'
  });

  const [isDark, setIsDark] = useState(() => {
    const saved = localStorage.getItem('theme');
    return saved ? saved === 'dark' : true;
  });

  useEffect(() => {
    if (isDark) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDark]);

  useEffect(() => {
    localStorage.setItem(DB_STORAGE_KEY, JSON.stringify(db));
  }, [db]);

  const handleNavigate = useCallback((view: ViewType, params?: Partial<NavigationState>) => {
    setNav(prev => ({ ...prev, view, ...params }));
  }, []);

  const handleBack = useCallback(() => {
    setNav(prev => {
      if (prev.view === 'ADMIN' || prev.view === 'MEGA_QUIZ') return { ...prev, view: 'HOME' };
      if (prev.view === 'QUIZ') return { ...prev, view: 'TOPICS' };
      if (prev.view === 'TOPICS') return { ...prev, view: 'SUBJECTS', selectedTopic: undefined };
      if (prev.view === 'SUBJECTS') return { ...prev, view: 'HOME', selectedSubject: undefined };
      return prev;
    });
  }, []);

  const handleImport = useCallback((data: AppDatabase) => {
    if (!data.results) data.results = {};
    if (!data.readingTexts) data.readingTexts = [];
    if (data.totalPracticed === undefined) data.totalPracticed = 0;
    setDb(data);
    alert('Base de datos importada con éxito.');
  }, []);

  const handleExport = useCallback(() => {
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(db, null, 2));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", `educasani_backup_${new Date().toISOString().split('T')[0]}.json`);
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  }, [db]);

  const saveQuestions = useCallback((newQuestions: Question[]) => {
    setDb(prev => ({
      ...prev,
      questions: [...prev.questions, ...newQuestions]
    }));
  }, []);

  const updateQuestion = useCallback((updatedQ: Question) => {
    setDb(prev => ({
      ...prev,
      questions: prev.questions.map(q => q.id === updatedQ.id ? updatedQ : q)
    }));
  }, []);

  const deleteQuestion = useCallback((id: string) => {
    setDb(prev => ({
      ...prev,
      questions: prev.questions.filter(q => q.id !== id)
    }));
  }, []);

  const saveReadingText = useCallback((text: ReadingText) => {
    setDb(prev => {
      const exists = prev.readingTexts?.find(t => t.id === text.id);
      if (exists) {
        return {
          ...prev,
          readingTexts: prev.readingTexts?.map(t => t.id === text.id ? text : t)
        };
      }
      return {
        ...prev,
        readingTexts: [...(prev.readingTexts || []), text]
      };
    });
  }, []);

  const deleteReadingText = useCallback((id: string) => {
    if (window.confirm("¿Seguro? Se desvincularán las preguntas asociadas.")) {
      setDb(prev => ({
        ...prev,
        readingTexts: prev.readingTexts?.filter(t => t.id !== id),
        questions: prev.questions.map(q => q.readingTextId === id ? { ...q, readingTextId: undefined } : q)
      }));
    }
  }, []);

  const deleteTopic = useCallback((topicName: string, subjectName: string) => {
    if (window.confirm(`¿Seguro que deseas eliminar la práctica "${topicName}"?`)) {
      setDb(prev => {
        const resultKey = `${subjectName}|${topicName}`;
        const newResults = { ...prev.results };
        delete newResults[resultKey];

        return {
          ...prev,
          questions: prev.questions.filter(q => !(q.topic === topicName && q.subject === subjectName)),
          results: newResults
        };
      });
    }
  }, []);

  const moveTopic = useCallback((topicName: string, subjectName: string, direction: 'UP' | 'DOWN') => {
    setDb(prev => {
      const subjectQuestions = prev.questions.filter(q => q.subject === subjectName);
      const otherQuestions = prev.questions.filter(q => q.subject !== subjectName);

      const uniqueTopics = Array.from(new Set(subjectQuestions.map(q => q.topic)))
        .map(t => ({
          name: t,
          order: subjectQuestions.find(q => q.topic === t)?.order ?? 999
        }))
        .sort((a, b) => a.order - b.order);

      const currentIndex = uniqueTopics.findIndex(t => t.name === topicName);
      if (currentIndex === -1) return prev;

      const targetIndex = direction === 'UP' ? currentIndex - 1 : currentIndex + 1;
      if (targetIndex < 0 || targetIndex >= uniqueTopics.length) return prev;

      const currentTopic = uniqueTopics[currentIndex];
      const targetTopic = uniqueTopics[targetIndex];
      const currentOrder = currentTopic.order;
      const targetOrder = targetTopic.order;

      const updatedSubjectQuestions = subjectQuestions.map(q => {
        if (q.topic === currentTopic.name) return { ...q, order: targetOrder };
        if (q.topic === targetTopic.name) return { ...q, order: currentOrder };
        return q;
      });

      return {
        ...prev,
        questions: [...otherQuestions, ...updatedSubjectQuestions]
      };
    });
  }, []);

  const handleFinishQuiz = useCallback((subject: string, topic: string, score: number, total: number) => {
    setDb(prev => ({
      ...prev,
      totalPracticed: (prev.totalPracticed || 0) + total,
      results: {
        ...prev.results,
        [`${subject}|${topic}`]: { score, total }
      }
    }));
  }, []);

  const handleResetPracticed = useCallback(() => {
    if (window.confirm("¿Deseas reiniciar el contador de flashcards practicadas?")) {
      setDb(prev => ({ ...prev, totalPracticed: 0 }));
    }
  }, []);

  const renderView = () => {
    switch (nav.view) {
      case 'HOME':
        return (
          <HomeView 
            onSelectCourse={(course) => handleNavigate('SUBJECTS', { selectedCourse: course })} 
            onStartMegaQuiz={() => handleNavigate('MEGA_QUIZ')}
          />
        );
      case 'SUBJECTS':
        return (
          <SubjectsView 
            courseName={nav.selectedCourse!} 
            onSelectSubject={(subject) => handleNavigate('TOPICS', { selectedSubject: subject })} 
          />
        );
      case 'TOPICS':
        return (
          <TopicsView 
            subjectName={nav.selectedSubject!} 
            questions={db.questions.filter(q => q.subject === nav.selectedSubject)}
            readingTexts={db.readingTexts || []}
            results={db.results || {}}
            onSelectTopic={(topic) => handleNavigate('QUIZ', { selectedTopic: topic })}
            onDeleteTopic={(topic) => deleteTopic(topic, nav.selectedSubject!)}
            onMoveTopic={(topic, dir) => moveTopic(topic, nav.selectedSubject!, dir)}
          />
        );
      case 'QUIZ':
        return (
          <QuizView 
            topicName={nav.selectedTopic!}
            subjectName={nav.selectedSubject!}
            questions={db.questions.filter(q => q.topic === nav.selectedTopic && q.subject === nav.selectedSubject)}
            readingTexts={db.readingTexts || []}
            onFinish={handleFinishQuiz}
          />
        );
      case 'MEGA_QUIZ':
        return (
          <MegaQuizView 
            questions={db.questions}
            readingTexts={db.readingTexts || []}
            onFinishMega={(total) => setDb(prev => ({ ...prev, totalPracticed: (prev.totalPracticed || 0) + total }))}
          />
        );
      case 'ADMIN':
        return (
          <AdminView 
            questions={db.questions}
            readingTexts={db.readingTexts || []}
            onSaveBatch={saveQuestions}
            onUpdateQuestion={updateQuestion}
            onDeleteQuestion={deleteQuestion}
            onSaveReadingText={saveReadingText}
            onDeleteReadingText={deleteReadingText}
          />
        );
      default:
        return <HomeView onSelectCourse={(course) => handleNavigate('SUBJECTS', { selectedCourse: course })} onStartMegaQuiz={() => handleNavigate('MEGA_QUIZ')} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-gray-50 dark:bg-slate-950 transition-colors duration-300">
      <Navbar 
        onNavigate={handleNavigate} 
        onBack={handleBack} 
        onImport={handleImport} 
        onExport={handleExport}
        onResetPracticed={handleResetPracticed}
        currentView={nav.view}
        navState={nav}
        isDark={isDark}
        toggleTheme={() => setIsDark(!isDark)}
        totalPracticed={db.totalPracticed || 0}
      />
      <main className="flex-grow container mx-auto px-4 py-8">
        {renderView()}
      </main>
      <footer className="bg-white dark:bg-slate-900 dark:border-slate-800 border-t py-6 text-center text-sm text-gray-500 dark:text-gray-400">
        &copy; {new Date().getFullYear()} EduCasani • Sistema de Gestión Académica
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Question, ReadingText } from '../types';
import { ACADEMIC_STRUCTURE } from '../constants';

interface AdminViewProps {
  questions: Question[];
  readingTexts: ReadingText[];
  onSaveBatch: (questions: Question[]) => void;
  onUpdateQuestion: (question: Question) => void;
  onDeleteQuestion: (id: string) => void;
  onSaveReadingText: (text: ReadingText) => void;
  onDeleteReadingText: (id: string) => void;
}

const AdminView: React.FC<AdminViewProps> = ({ 
  questions, 
  readingTexts, 
  onSaveBatch, 
  onUpdateQuestion, 
  onDeleteQuestion,
  onSaveReadingText,
  onDeleteReadingText
}) => {
  const [activeTab, setActiveTab] = useState<'EDITOR' | 'MANAGE' | 'TEXTS'>('EDITOR');
  const [currentBatch, setCurrentBatch] = useState<Question[]>([]);

  // Form State Question
  const [editingId, setEditingId] = useState<string | null>(null);
  const [course, setCourse] = useState('');
  const [subject, setSubject] = useState('');
  const [topic, setTopic] = useState('');
  const [questionText, setQuestionText] = useState('');
  const [options, setOptions] = useState<string[]>(['', '', '', '', '']);
  const [correctIndex, setCorrectIndex] = useState(0);
  const [explanation, setExplanation] = useState('');
  const [readingTextId, setReadingTextId] = useState('');

  // Form State ReadingText
  const [editingTextId, setEditingTextId] = useState<string | null>(null);
  const [textTitle, setTextTitle] = useState('');
  const [textContent, setTextContent] = useState('');
  const [textSubject, setTextSubject] = useState('Comprensión Lectora');

  const isBatchStarted = currentBatch.length > 0;
  const isEditing = !!editingId;

  const currentCourse = ACADEMIC_STRUCTURE.find(c => c.name === course);
  const availableSubjects = currentCourse?.subjects || [];

  const resetForm = (full: boolean = true) => {
    setQuestionText('');
    setOptions(['', '', '', '', '']);
    setCorrectIndex(0);
    setExplanation('');
    setEditingId(null);
    setReadingTextId('');
    if (full) {
      setCourse('');
      setSubject('');
      setTopic('');
    }
  };

  const resetTextForm = () => {
    setTextTitle('');
    setTextContent('');
    setTextSubject('Comprensión Lectora');
    setEditingTextId(null);
  };

  const handleAddOrUpdate = () => {
    if (!course || !subject || !topic || !questionText || options.some(o => !o) || !explanation) {
      alert("Por favor completa todos los campos.");
      return;
    }

    if (subject === 'Comprensión Lectora' && !readingTextId) {
      alert("Para Comprensión Lectora debes vincular un Texto de Lectura.");
      return;
    }

    const qData = {
      course,
      subject,
      topic,
      questionText,
      options: [...options],
      correctIndex,
      explanation,
      readingTextId: readingTextId || undefined
    };

    if (isEditing) {
      const updatedQ: Question = {
        ...qData,
        id: editingId!,
        order: questions.find(q => q.id === editingId)?.order ?? 999,
        createdAt: questions.find(q => q.id === editingId)?.createdAt ?? Date.now()
      } as Question;
      onUpdateQuestion(updatedQ);
      alert("Pregunta actualizada.");
      resetForm();
      setActiveTab('MANAGE');
    } else {
      const newQ: Question = {
        ...qData,
        id: crypto.randomUUID(),
        order: 999,
        createdAt: Date.now()
      } as Question;
      setCurrentBatch(prev => [...prev, newQ]);
      resetForm(false); 
    }
  };

  const handleSaveReadingTextLocal = () => {
    if (!textTitle || !textContent || !textSubject) {
      alert("Completa el título y contenido del texto.");
      return;
    }
    const newText: ReadingText = {
      id: editingTextId || crypto.randomUUID(),
      title: textTitle,
      content: textContent,
      subject: textSubject
    };
    onSaveReadingText(newText);
    resetTextForm();
    alert("Texto guardado.");
  };

  const handleEditExisting = (q: Question) => {
    setEditingId(q.id);
    setCourse(q.course);
    setSubject(q.subject);
    setTopic(q.topic);
    setQuestionText(q.questionText);
    setOptions([...q.options]);
    setCorrectIndex(q.correctIndex);
    setExplanation(q.explanation);
    setReadingTextId(q.readingTextId || '');
    setActiveTab('EDITOR');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleEditExistingText = (t: ReadingText) => {
    setEditingTextId(t.id);
    setTextTitle(t.title);
    setTextContent(t.content);
    setTextSubject(t.subject);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleSaveAllBatch = () => {
    if (currentBatch.length === 0) return;
    onSaveBatch(currentBatch);
    setCurrentBatch([]);
    resetForm();
    alert("Práctica guardada correctamente.");
  };

  const handleOptionChange = (idx: number, val: string) => {
    const newOpts = [...options];
    newOpts[idx] = val;
    setOptions(newOpts);
  };

  const [manageFilterCourse, setManageFilterCourse] = useState('');
  const [manageFilterSubject, setManageFilterSubject] = useState('');

  const filteredQuestions = useMemo(() => {
    return questions.filter(q => {
      const matchCourse = !manageFilterCourse || q.course === manageFilterCourse;
      const matchSubject = !manageFilterSubject || q.subject === manageFilterSubject;
      return matchCourse && matchSubject;
    });
