          className={`px-6 py-2.5 rounded-xl font-bold text-sm transition-all ${activeTab === 'EDITOR' ? 'bg-white dark:bg-slate-800 text-indigo-700 dark:text-indigo-300 shadow-md' : 'text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-300'}`}
        >
