import React, { useState, useMemo, useEffect } from 'react';
import { Question, ReadingText } from '../types';
import { MEGA_EXAM_CONFIG } from '../constants';

interface MegaQuizViewProps {
  questions: Question[];
  readingTexts: ReadingText[];
  onFinishMega: (total: number) => void;
}

const MegaQuizView: React.FC<MegaQuizViewProps> = ({ questions, readingTexts, onFinishMega }) => {
  const [answers, setAnswers] = useState<Record<string, number>>({});
  const [isFinished, setIsFinished] = useState(false);

  const INITIAL_TIME = 9000;
  const [timeLeft, setTimeLeft] = useState(INITIAL_TIME);

  useEffect(() => {
    if (isFinished) return;
    if (timeLeft <= 0) { handleFinalize(); return; }
    const timer = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    return () => clearInterval(timer);
  }, [timeLeft, isFinished]);

  const formatTime = (seconds: number) => {
    const hrs = Math.floor(seconds / 3600);
    const mins = Math.floor((seconds % 3600) / 60);
    const secs = seconds % 60;
    return `${hrs.toString().padStart(2, '0')}:${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const selectedQuestions = useMemo(() => {
    const finalSelection: { question: Question; weight: number; category: string; readingText?: ReadingText }[] = [];

    Object.entries(MEGA_EXAM_CONFIG).forEach(([categoryName, config]) => {
      if (categoryName === 'Comprensión Lectora') {
        const pool = questions.filter(q => q.subject === 'Comprensión Lectora' && q.readingTextId);
        const groupedByText: Record<string, Question[]> = {};

        pool.forEach(q => {
          if (q.readingTextId) {
            if (!groupedByText[q.readingTextId]) groupedByText[q.readingTextId] = [];
            groupedByText[q.readingTextId].push(q);
          }
        });

        const textIds = Object.keys(groupedByText).sort(() => 0.5 - Math.random());

        if (textIds[0]) {
          const text1 = readingTexts.find(t => t.id === textIds[0]);
          const qs1 = [...groupedByText[textIds[0]]].sort(() => 0.5 - Math.random()).slice(0, 3);
          qs1.forEach(q => finalSelection.push({ question: q, weight: config.weight, category: categoryName, readingText: text1 }));
        }

        if (textIds[1]) {
          const text2 = readingTexts.find(t => t.id === textIds[1]);
          const qs2 = [...groupedByText[textIds[1]]].sort(() => 0.5 - Math.random()).slice(0, 2);
          qs2.forEach(q => finalSelection.push({ question: q, weight: config.weight, category: categoryName, readingText: text2 }));
        }
      } else {
        const pool = questions.filter(q => config.subjects.includes(q.subject));
        const shuffled = [...pool].sort(() => 0.5 - Math.random());
        const selected = shuffled.slice(0, config.count);
        selected.forEach(q => finalSelection.push({ question: q, weight: config.weight, category: categoryName }));
      }
    });

    return finalSelection.sort(() => 0.5 - Math.random());
  }, [questions, readingTexts]);

  const renderGroups = useMemo(() => {
    const groups: { readingText?: ReadingText, items: typeof selectedQuestions }[] = [];
    const processedQuestionIds = new Set<string>();

    selectedQuestions.forEach(item => {
      if (processedQuestionIds.has(item.question.id)) return;

      if (item.readingText) {
        const sharedTextItems = selectedQuestions.filter(i => i.readingText?.id === item.readingText?.id);
        groups.push({ readingText: item.readingText, items: sharedTextItems });
        sharedTextItems.forEach(i => processedQuestionIds.add(i.question.id));
      } else {
        groups.push({ items: [item] });
        processedQuestionIds.add(item.question.id);
      }
    });

    return groups;
  }, [selectedQuestions]);

  const handleSelect = (qId: string, optIndex: number) => {
    if (isFinished) return;
    setAnswers(prev => ({ ...prev, [qId]: optIndex }));
  };

  const handleFinalize = () => {
    if (isFinished) return;
    setIsFinished(true);
    onFinishMega(selectedQuestions.length);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const calculateDetailedResults = () => {
    const breakdown: Record<string, { correct: number; total: number; points: number; maxPoints: number }> = {};
    let totalScore = 0;
    selectedQuestions.forEach(item => {
      if (!breakdown[item.category]) breakdown[item.category] = { correct: 0, total: 0, points: 0, maxPoints: 0 };
      breakdown[item.category].total += 1;
      breakdown[item.category].maxPoints += item.weight;
      if (answers[item.question.id] === item.question.correctIndex) {
        breakdown[item.category].correct += 1;
        breakdown[item.category].points += item.weight;
        totalScore += item.weight;
      }
    });
    return { totalScore, breakdown };
  };

  const results = useMemo(() => calculateDetailedResults(), [isFinished, answers, selectedQuestions]);

  if (selectedQuestions.length === 0) {
    return <div className="max-w-2xl mx-auto py-20 text-center bg-white dark:bg-slate-900 rounded-3xl border dark:border-slate-800 shadow-xl">⚠️ No hay preguntas suficientes.</div>;
  }

  return (
    <div className="max-w-5xl mx-auto">
      <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-xl border border-gray-100 dark:border-slate-800 p-8 mb-8 sticky top-[80px] z-40 flex flex-col md:flex-row items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-gray-800 dark:text-gray-100 tracking-tight">Simulacro General 80</h2>
          <p className="text-gray-400 text-sm">Tiempo restante: {formatTime(timeLeft)}</p>
        </div>
        {!isFinished ? (
          <button onClick={handleFinalize} className="bg-indigo-600 text-white px-10 py-4 rounded-2xl font-black hover:bg-indigo-700 shadow-xl active:scale-95 transition-all text-lg">Finalizar</button>
        ) : (
          <div className="text-center px-8 py-3 bg-indigo-50 dark:bg-indigo-900/30 border-2 border-indigo-200 dark:border-indigo-800 rounded-2xl">
            <span className="text-[10px] uppercase font-black text-indigo-400 block tracking-widest">Puntaje Total</span>
            <span className="text-4xl font-black text-indigo-700 dark:text-indigo-200">{results.totalScore.toFixed(4)} / 100.00</span>
          </div>
        )}
      </div>

      <div className="space-y-16 pb-20">
        {renderGroups.map((group, gIdx) => (
          <div key={gIdx} className="space-y-8">
            {group.readingText && (
              <div className="bg-amber-50 dark:bg-amber-900/10 border-l-8 border-amber-400 rounded-r-3xl p-8 md:p-12 shadow-sm">
                <div className="flex items-center gap-2 mb-4 text-amber-600 dark:text-amber-400 font-black text-xs uppercase tracking-widest">
                  <span>📖</span> TEXTO DE COMPRENSIÓN LECTORA
                </div>
                <h4 className="text-2xl font-black text-gray-800 dark:text-gray-100 mb-6 font-serif">{group.readingText.title}</h4>
                <div className="text-gray-700 dark:text-gray-200 leading-relaxed font-serif whitespace-pre-wrap text-xl italic bg-white/40 dark:bg-slate-900/40 p-6 rounded-xl border border-amber-100 dark:border-amber-900/30">
                  {group.readingText.content}
                </div>
              </div>
            )}

            {group.items.map((item, idx) => {
              const q = item.question;
              const selected = answers[q.id];
              const isCorrect = selected === q.correctIndex;
              const globalIdx = selectedQuestions.indexOf(item) + 1;

              return (
                <div key={q.id} className={`bg-white dark:bg-slate-900 rounded-3xl border transition-all duration-300 ${isFinished ? (isCorrect ? 'border-emerald-200 shadow-emerald-50 dark:border-emerald-800' : 'border-rose-200 shadow-rose-50 dark:border-rose-800') : 'border-gray-100 dark:border-slate-800 shadow-sm'}`}>
                  <div className="p-6 md:p-10">
                    <div className="flex items-center gap-4 mb-6">
                      <span className="bg-gray-800 text-white font-black w-10 h-10 rounded-xl flex items-center justify-center shrink-0">{globalIdx}</span>
                      <span className="bg-indigo-50 dark:bg-indigo-900/50 text-indigo-600 dark:text-indigo-400 text-[10px] font-black px-2 py-0.5 rounded uppercase">{item.category}</span>
                    </div>

                    {q.imageUrl && (
                      <div className="mb-8 rounded-3xl overflow-hidden border dark:border-slate-800 shadow-sm bg-gray-50 dark:bg-slate-800/50">
                        <img 
                          src={q.imageUrl} 
                          alt="Illustration" 
                          className="max-w-full h-auto mx-auto max-h-[500px] object-contain" 
                        />
                      </div>
                    )}

                    <p className="text-xl font-bold text-gray-800 dark:text-gray-100 leading-relaxed mb-8 whitespace-pre-wrap">{q.questionText}</p>

                    <div className="grid grid-cols-1 gap-3">
                      {q.options.map((opt, optIdx) => {
                        const isUserSelection = selected === optIdx;
                        const isCorrectAnswer = optIdx === q.correctIndex;
                        let bgColor = "bg-gray-50 dark:bg-slate-800 border-gray-100 dark:border-slate-700";
                        if (isFinished) {
                          if (isCorrectAnswer) bgColor = "bg-emerald-50 dark:bg-emerald-900/30 border-emerald-500 ring-2 ring-emerald-500";
                          else if (isUserSelection) bgColor = "bg-rose-50 dark:bg-rose-900/30 border-rose-500 ring-2 ring-rose-500";
                          else bgColor = "opacity-40";
                        } else if (isUserSelection) bgColor = "bg-indigo-50 dark:bg-indigo-900/50 border-indigo-500 ring-2 ring-indigo-500";

                        return (
                          <button key={optIdx} disabled={isFinished} onClick={() => handleSelect(q.id, optIdx)} className={`text-left p-5 rounded-2xl border-2 transition-all flex items-center gap-4 ${bgColor}`}>
                            <div className={`w-8 h-8 rounded-xl border-2 flex items-center justify-center font-black ${isUserSelection ? 'bg-indigo-600 border-indigo-600 text-white' : 'text-gray-400'}`}>{String.fromCharCode(65 + optIdx)}</div>
                            <span className="font-medium text-gray-700 dark:text-gray-200 whitespace-pre-wrap">{opt}</span>
                          </button>
                        );
                      })}
                    </div>
                    {isFinished && (
                      <div className="mt-8 bg-indigo-50/30 dark:bg-indigo-900/20 p-6 rounded-2xl border dark:border-indigo-900/30">
                        <p className="text-indigo-900 dark:text-indigo-200 font-bold mb-2">Respuesta: {q.options[q.correctIndex]}</p>
                        <p className="text-gray-500 dark:text-gray-400 italic text-sm whitespace-pre-wrap">{q.explanation}</p>
                      </div>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        ))}
      </div>
    </div>
  );
};

export default MegaQuizView;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Question, ReadingText } from '../types';

interface QuizViewProps {
  topicName: string;
  subjectName: string;
  questions: Question[];
  readingTexts: ReadingText[];
  onFinish: (subject: string, topic: string, score: number, total: number) => void;
}

const QuizView: React.FC<QuizViewProps> = ({ topicName, subjectName, questions, readingTexts, onFinish }) => {
  const [answers, setAnswers] = useState<Record<string, number>>({});
  const [isFinished, setIsFinished] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  // Efecto para renderizar KaTeX cada vez que cambia el contenido o el estado
  useEffect(() => {
    if (containerRef.current && (window as any).renderMathInElement) {
      (window as any).renderMathInElement(containerRef.current, {
        delimiters: [
          { left: '$$', right: '$$', display: true },
          { left: '$', right: '$', display: false }
        ],
        throwOnError: false
      });
    }
  }, [questions, isFinished, answers]);

  const groupedQuestions = useMemo(() => {
    const groups: { text?: ReadingText, questions: Question[] }[] = [];
    const textIds = Array.from(new Set(questions.map(q => q.readingTextId)));

    textIds.forEach(id => {
      const qs = questions.filter(q => q.readingTextId === id);
      const text = readingTexts.find(t => t.id === id);
      groups.push({ text, questions: qs });
    });

    return groups;
  }, [questions, readingTexts]);

  const handleSelect = (qId: string, optIndex: number) => {
    if (isFinished) return;
    setAnswers(prev => ({ ...prev, [qId]: optIndex }));
  };

  const handleGrade = () => {
    let score = 0;
    questions.forEach(q => {
      if (answers[q.id] === q.correctIndex) score++;
    });
    setIsFinished(true);
    onFinish(subjectName, topicName, score, questions.length);
  };

  const score = useMemo(() => {
    let s = 0;
    questions.forEach(q => {
      if (answers[q.id] === q.correctIndex) s++;
    });
    return s;
  }, [answers, questions]);

  return (
    <div className="max-w-4xl mx-auto" ref={containerRef}>
      <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-gray-100 dark:border-slate-800 p-6 mb-8 sticky top-[80px] z-40 flex flex-col md:flex-row items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-black text-gray-800 dark:text-gray-100">{topicName}</h2>
          <p className="text-gray-400 dark:text-gray-500 text-sm">Responde con precisión. Usa notación $Latex$ si es necesario.</p>
        </div>
        {!isFinished ? (
          <button 
            onClick={handleGrade}
            className="w-full md:w-auto bg-indigo-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-indigo-700 shadow-md transition-all"
          >
            Calificar Simulacro
          </button>
        ) : (
          <div className="text-center px-6 py-2 bg-indigo-50 dark:bg-indigo-900/30 border border-indigo-200 dark:border-indigo-800 rounded-xl">
            <span className="text-xs uppercase font-black text-indigo-400 dark:text-indigo-300 block tracking-widest">Puntaje Final</span>
            <span className="text-3xl font-black text-indigo-700 dark:text-indigo-200">{score} / {questions.length}</span>
          </div>
        )}
      </div>

      <div className="space-y-12 pb-24">
        {groupedQuestions.map((group, groupIdx) => (
          <div key={groupIdx} className="space-y-8">
            {group.text && (
              <div className="bg-slate-50 dark:bg-slate-800/40 border-l-4 border-indigo-500 rounded-r-2xl p-6 md:p-8 shadow-inner">
                <h3 className="text-indigo-600 dark:text-indigo-400 font-black uppercase text-xs tracking-widest mb-4">LECTURA ASOCIADA</h3>
                <h4 className="text-xl font-bold text-gray-800 dark:text-gray-100 mb-4">{group.text.title}</h4>
                <div className="text-gray-600 dark:text-gray-300 leading-relaxed font-serif whitespace-pre-wrap text-lg italic">
                  {group.text.content}
                </div>
              </div>
            )}

            {group.questions.map((q, qIdx) => {
              const selected = answers[q.id];
              const isCorrect = selected === q.correctIndex;
              const globalIdx = questions.indexOf(q) + 1;

              return (
                <div key={q.id} className="bg-white dark:bg-slate-900 rounded-2xl border border-gray-100 dark:border-slate-800 shadow-sm p-6 md:p-8">
                  <div className="flex items-start gap-4 mb-6">
                    <span className="bg-gray-100 dark:bg-slate-800 text-gray-500 dark:text-gray-400 font-bold w-10 h-10 rounded-full flex items-center justify-center shrink-0">
                      {globalIdx}
                    </span>
                    <div className="flex-grow pt-1 overflow-x-auto">
                      {q.imageUrl && (
                        <div className="mb-6 rounded-2xl overflow-hidden border dark:border-slate-800 shadow-inner bg-gray-50 dark:bg-slate-800/50">
                          <img 
                            src={q.imageUrl} 
                            alt="Question Illustration" 
                            className="max-w-full h-auto mx-auto max-h-[400px] object-contain" 
                          />
                        </div>
                      )}
                      <p className="text-lg font-medium text-gray-800 dark:text-gray-200 leading-relaxed whitespace-pre-wrap">
                        {q.questionText}
                      </p>
                    </div>
                  </div>

                  <div className="grid grid-cols-1 gap-3 ml-0 md:ml-14">
                    {q.options.map((opt, optIdx) => {
                      const isUserSelection = selected === optIdx;
                      const isCorrectAnswer = optIdx === q.correctIndex;

                      let bgColor = "bg-white dark:bg-slate-800 border-gray-200 dark:border-slate-700 hover:bg-gray-50 dark:hover:bg-slate-700/50";
                      let textColor = "text-gray-700 dark:text-gray-300";
                      let borderColor = "border-gray-200 dark:border-slate-700";

                      if (isFinished) {
                        if (isCorrectAnswer) {
                          bgColor = "bg-emerald-50 dark:bg-emerald-900/30 border-emerald-500 ring-1 ring-emerald-500";
                          textColor = "text-emerald-800 dark:text-emerald-200";
                        } else if (isUserSelection && !isCorrect) {
                          bgColor = "bg-rose-50 dark:bg-rose-900/30 border-rose-500 ring-1 ring-rose-500";
                          textColor = "text-rose-800 dark:text-rose-200";
                        } else {
                          bgColor = "bg-white dark:bg-slate-900 opacity-60 border-gray-200 dark:border-slate-800";
                        }
                      } else if (isUserSelection) {
                        bgColor = "bg-indigo-50 dark:bg-indigo-900/30 border-indigo-500 ring-1 ring-indigo-500";
                        textColor = "text-indigo-800 dark:text-indigo-200";
                      }

                      return (
                        <button
                          key={optIdx}
                          disabled={isFinished}
                          onClick={() => handleSelect(q.id, optIdx)}
                          className={`relative text-left p-4 rounded-xl border transition-all flex items-center gap-4 ${bgColor} ${textColor} ${borderColor} overflow-hidden`}
                        >
                          <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center shrink-0 ${isUserSelection ? 'bg-indigo-600 border-indigo-600' : 'border-gray-300 dark:border-slate-600'}`}>
                            {isUserSelection && <div className="w-2 h-2 bg-white rounded-full"></div>}
                          </div>
                          <span className="flex-grow whitespace-pre-wrap overflow-x-auto">{opt}</span>
                        </button>
                      );
                    })}
                  </div>

                  {isFinished && (
                    <div className="mt-6 ml-0 md:ml-14 bg-indigo-50/50 dark:bg-indigo-900/20 p-5 rounded-xl border border-indigo-100 dark:border-indigo-900/50 overflow-x-auto">
                      <p className="text-indigo-800 dark:text-indigo-200 mb-2 font-bold">Respuesta correcta: {q.options[q.correctIndex]}</p>
                      <p className="text-gray-600 dark:text-gray-400 text-sm italic leading-relaxed whitespace-pre-wrap">{q.explanation}</p>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        ))}
      </div>
    </div>
  );
};

export default QuizView;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Question, ReadingText } from '../types';
import { ACADEMIC_STRUCTURE } from '../constants';

interface AdminViewProps {
  questions: Question[];
  readingTexts: ReadingText[];
  onSaveBatch: (questions: Question[]) => void;
  onUpdateQuestion: (question: Question) => void;
  onDeleteQuestion: (id: string) => void;
  onSaveReadingText: (text: ReadingText) => void;
  onDeleteReadingText: (id: string) => void;
}

const AdminView: React.FC<AdminViewProps> = ({ 
  questions, 
  readingTexts, 
  onSaveBatch, 
  onUpdateQuestion, 
  onDeleteQuestion,
  onSaveReadingText,
  onDeleteReadingText
}) => {
  const [activeTab, setActiveTab] = useState<'EDITOR' | 'MANAGE' | 'TEXTS'>('EDITOR');
  const [currentBatch, setCurrentBatch] = useState<Question[]>([]);

  // Form State Question
  const [editingId, setEditingId] = useState<string | null>(null);
  const [course, setCourse] = useState('');
  const [subject, setSubject] = useState('');
  const [topic, setTopic] = useState('');
  const [questionText, setQuestionText] = useState('');
  const [options, setOptions] = useState<string[]>(['', '', '', '', '']);
  const [correctIndex, setCorrectIndex] = useState(0);
  const [explanation, setExplanation] = useState('');
  const [readingTextId, setReadingTextId] = useState('');
  const [imageUrl, setImageUrl] = useState('');

  const previewRef = useRef<HTMLDivElement>(null);

  // Efecto para renderizar KaTeX en la vista previa del editor
  useEffect(() => {
    if (previewRef.current && (window as any).renderMathInElement) {
      (window as any).renderMathInElement(previewRef.current, {
        delimiters: [
          { left: '$$', right: '$$', display: true },
          { left: '$', right: '$', display: false }
        ],
        throwOnError: false
      });
    }
  }, [questionText, options, explanation, activeTab]);

  // Form State ReadingText
  const [editingTextId, setEditingTextId] = useState<string | null>(null);
  const [textTitle, setTextTitle] = useState('');
  const [textContent, setTextContent] = useState('');
  const [textSubject, setTextSubject] = useState('Comprensión Lectora');

  const isBatchStarted = currentBatch.length > 0;
  const isEditing = !!editingId;

  const currentCourse = ACADEMIC_STRUCTURE.find(c => c.name === course);
  const availableSubjects = currentCourse?.subjects || [];

  const resetForm = (full: boolean = true) => {
    setQuestionText('');
    setOptions(['', '', '', '', '']);
    setCorrectIndex(0);
    setExplanation('');
    setEditingId(null);
    setReadingTextId('');
    setImageUrl('');
    if (full) {
      setCourse('');
      setSubject('');
      setTopic('');
    }
  };

  const resetTextForm = () => {
    setTextTitle('');
    setTextContent('');
    setTextSubject('Comprensión Lectora');
    setEditingTextId(null);
  };

  const handleAddOrUpdate = () => {
    if (!course || !subject || !topic || !questionText || options.some(o => !o) || !explanation) {
      alert("Por favor completa todos los campos.");
      return;
    }

    const qData = {
      course,
      subject,
      topic,
      questionText,
      options: [...options],
      correctIndex,
      explanation,
      readingTextId: readingTextId || undefined,
      imageUrl: imageUrl || undefined
    };

    if (isEditing) {
      const updatedQ: Question = {
        ...qData,
        id: editingId!,
        order: questions.find(q => q.id === editingId)?.order ?? 999,
        createdAt: questions.find(q => q.id === editingId)?.createdAt ?? Date.now()
      } as Question;
      onUpdateQuestion(updatedQ);
      alert("Pregunta actualizada.");
      resetForm();
      setActiveTab('MANAGE');
    } else {
      const newQ: Question = {
        ...qData,
        id: crypto.randomUUID(),
        order: 999,
        createdAt: Date.now()
      } as Question;
      setCurrentBatch(prev => [...prev, newQ]);
      resetForm(false); 
    }
  };

  const handleSaveReadingTextLocal = () => {
    if (!textTitle || !textContent || !textSubject) {
      alert("Completa el título y contenido del texto.");
      return;
    }
    const newText: ReadingText = {
      id: editingTextId || crypto.randomUUID(),
      title: textTitle,
      content: textContent,
      subject: textSubject
    };
    onSaveReadingText(newText);
    resetTextForm();
    alert("Texto guardado.");
  };

  const handleEditExisting = (q: Question) => {
    setEditingId(q.id);
    setCourse(q.course);
    setSubject(q.subject);
    setTopic(q.topic);
    setQuestionText(q.questionText);
    setOptions([...q.options]);
    setCorrectIndex(q.correctIndex);
    setExplanation(q.explanation);
    setReadingTextId(q.readingTextId || '');
    setImageUrl(q.imageUrl || '');
    setActiveTab('EDITOR');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleEditExistingText = (t: ReadingText) => {
    setEditingTextId(t.id);
    setTextTitle(t.title);
    setTextContent(t.content);
    setTextSubject(t.subject);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleDeleteExisting = (id: string) => {
    if (window.confirm("¿Estás seguro de que deseas eliminar esta pregunta del banco?")) {
      onDeleteQuestion(id);
    }
  };

  const handleSaveAllBatch = () => {
    if (currentBatch.length === 0) return;
    onSaveBatch(currentBatch);
    setCurrentBatch([]);
    resetForm();
    alert("Práctica guardada correctamente.");
  };

  const handleOptionChange = (idx: number, val: string) => {
    const newOpts = [...options];
    newOpts[idx] = val;
    setOptions(newOpts);
  };

  const filteredQuestions = useMemo(() => {
    const courseFilter = questions.filter(q => !course || q.course === course);
    return courseFilter.filter(q => !subject || q.subject === subject);
  }, [questions, course, subject]);

  return (
    <div className="max-w-7xl mx-auto">
      {/* Tab Switcher */}
      <div className="flex flex-wrap bg-gray-100 dark:bg-slate-900 p-1.5 rounded-2xl w-fit mb-8 mx-auto border border-gray-200 dark:border-slate-800 shadow-inner">
        <button 
          onClick={() => { setActiveTab('EDITOR'); if(!isEditing) resetForm(); }}
          className={`px-6 py-2.5 rounded-xl font-bold text-sm transition-all ${activeTab === 'EDITOR' ? 'bg-white dark:bg-slate-800 text-indigo-700 dark:text-indigo-300 shadow-md' : 'text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-300'}`}
        >
          {isEditing ? 'Editando Pregunta' : 'Añadir Preguntas'}
        </button>
        <button 
          onClick={() => setActiveTab('TEXTS')}
          className={`px-6 py-2.5 rounded-xl font-bold text-sm transition-all ${activeTab === 'TEXTS' ? 'bg-white dark:bg-slate-800 text-indigo-700 dark:text-indigo-300 shadow-md' : 'text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-300'}`}
        >
          Gestionar Lecturas
        </button>
        <button 
          onClick={() => setActiveTab('MANAGE')}
          className={`px-6 py-2.5 rounded-xl font-bold text-sm transition-all ${activeTab === 'MANAGE' ? 'bg-white dark:bg-slate-800 text-indigo-700 dark:text-indigo-300 shadow-md' : 'text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-300'}`}
        >
          Gestionar Banco ({questions.length})
        </button>
      </div>

      {activeTab === 'EDITOR' && (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
