                  <div className="p-1 bg-white/50 dark:bg-slate-800 rounded">Raíz: {'$\\sqrt{x}$'}</div>
                  <div className="p-1 bg-white/50 dark:bg-slate-800 rounded">Fracción: {'$\\frac{a}{b}$'}</div>
                  <div className="p-1 bg-white/50 dark:bg-slate-800 rounded">Base: {'$log_{b}$'}</div>
                </div>
                <p className="mt-2 text-[9px] text-amber-600 dark:text-amber-500">Encierra las fórmulas entre signos de dólar ($) para activarlas.</p>
              </div>

              <div className="space-y-6">
                <div>
                  <label className="block text-xs font-black text-gray-400 dark:text-gray-500 uppercase tracking-widest mb-2">Enunciado de la Pregunta</label>
                  <textarea 
                    value={questionText}
                    onChange={(e) => setQuestionText(e.target.value)}
                    className="w-full bg-gray-50 dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-xl p-4 min-h-[100px] outline-none dark:text-gray-200 whitespace-pre-wrap"
                    placeholder="Escribe la pregunta aquí..."
                  />
                </div>

                <div className="space-y-3">
                  <label className="block text-xs font-black text-gray-400 dark:text-gray-500 uppercase tracking-widest mb-1">Alternativas</label>
                  {options.map((opt, idx) => (
                    <div key={idx} className="flex gap-3 items-center">
                      <input 
                        type="radio" 
                        name="correct" 
                        checked={correctIndex === idx} 
                        onChange={() => setCorrectIndex(idx)}
                        className="w-5 h-5 accent-indigo-600"
                      />
                      <textarea 
                        value={opt}
                        onChange={(e) => handleOptionChange(idx, e.target.value)}
                        placeholder={`Alternativa ${String.fromCharCode(65 + idx)}`}
                        className="flex-grow bg-gray-50 dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-xl p-3 outline-none dark:text-gray-200 min-h-[60px] whitespace-pre-wrap"
                      />
