                  ))}
                </div>

                <div>
                  <label className="block text-xs font-black text-gray-400 dark:text-gray-500 uppercase tracking-widest mb-2">Explicación</label>
                  <textarea 
                    value={explanation}
                    onChange={(e) => setExplanation(e.target.value)}
                    className="w-full bg-gray-50 dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-xl p-4 min-h-[80px] outline-none dark:text-gray-200 whitespace-pre-wrap"
                    placeholder="Retroalimentación..."
                  />
                </div>

                <button 
                  onClick={handleAddOrUpdate}
                  className="w-full py-4 rounded-xl font-bold bg-indigo-600 text-white hover:bg-indigo-700 shadow-lg transition-all"
                >
                  {isEditing ? 'Actualizar Pregunta' : 'Añadir a la lista temporal'}
                </button>
              </div>
            </div>
          </div>

          <div className="lg:col-span-5 space-y-6">
            {/* Vista Previa en Tiempo Real */}
            <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-gray-100 dark:border-slate-800 p-6 md:p-8 sticky top-[100px]">
              <h3 className="text-xl font-bold text-gray-800 dark:text-gray-100 mb-6 flex items-center gap-2">
                <span>👁️</span> Vista Previa Real
              </h3>
              <div ref={previewRef} className="space-y-4 max-h-[70vh] overflow-y-auto pr-2">
                <div className="p-4 bg-gray-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl">
                   <p className="text-sm text-gray-800 dark:text-gray-100 whitespace-pre-wrap">
                     {questionText || '(Escribe algo para ver la vista previa...)'}
                   </p>
                </div>
                <div className="space-y-2">
                  {options.map((opt, i) => (
                    opt && (
                      <div key={i} className="p-3 bg-white dark:bg-slate-900 border dark:border-slate-800 rounded-lg text-xs text-gray-600 dark:text-gray-300 flex items-center gap-3">
                         <span className="font-bold opacity-50">{String.fromCharCode(65 + i)})</span>
                         <span className="whitespace-pre-wrap">{opt}</span>
                      </div>
                    )
                  ))}
                </div>
                {explanation && (
                  <div className="mt-4 p-3 bg-indigo-50 dark:bg-indigo-900/20 border-l-4 border-indigo-400 rounded-r-lg text-xs italic dark:text-indigo-200 whitespace-pre-wrap">
                    {explanation}
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'TEXTS' && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-gray-100 dark:border-slate-800 p-8">
            <h2 className="text-2xl font-black text-gray-800 dark:text-gray-100 mb-6 flex items-center gap-3">
              <span>📖</span> {editingTextId ? 'Editar Lectura' : 'Nueva Lectura'}
            </h2>
            <div className="space-y-4">
              <div>
                <label className="block text-xs font-black text-gray-400 uppercase mb-2">Título del Texto</label>
                <input 
                  type="text" 
                  value={textTitle} 
                  onChange={(e) => setTextTitle(e.target.value)}
                  className="w-full bg-gray-50 dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-xl p-3 outline-none dark:text-gray-200"
                  placeholder="Ej. El Principito - Capítulo 1"
                />
              </div>
              <div>
                <label className="block text-xs font-black text-gray-400 uppercase mb-2">Contenido de la Lectura</label>
                <textarea 
                  value={textContent}
                  onChange={(e) => setTextContent(e.target.value)}
                  className="w-full bg-gray-50 dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-xl p-4 min-h-[300px] outline-none dark:text-gray-200 font-serif leading-relaxed whitespace-pre-wrap"
                  placeholder="Pega aquí el texto completo..."
                />
              </div>
              <button 
                onClick={handleSaveReadingTextLocal}
                className="w-full py-4 rounded-xl font-bold bg-indigo-600 text-white hover:bg-indigo-700 shadow-lg transition-all"
              >
                Guardar Lectura
              </button>
            </div>
          </div>

          <div className="space-y-4">
            <h3 className="text-xl font-bold text-gray-800 dark:text-gray-100 mb-4">Lecturas Registradas ({readingTexts.length})</h3>
            {readingTexts.map(t => (
              <div key={t.id} className="bg-white dark:bg-slate-900 border border-gray-100 dark:border-slate-800 rounded-xl p-5 shadow-sm hover:shadow-md transition-all group">
                <div className="flex justify-between items-start">
                  <div>
                    <h4 className="font-bold text-gray-800 dark:text-gray-100">{t.title}</h4>
                    <p className="text-xs text-gray-400 mt-1 line-clamp-2 italic">{t.content}</p>
                  </div>
                  <div className="flex gap-2">
                    <button onClick={() => handleEditExistingText(t)} className="p-2 text-indigo-400 hover:bg-indigo-50 dark:hover:bg-slate-800 rounded-lg transition-colors">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                      </svg>
                    </button>
                    <button onClick={() => onDeleteReadingText(t.id)} className="p-2 text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/30 rounded-lg transition-colors">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                      </svg>
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'MANAGE' && (
        <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-gray-100 dark:border-slate-800 p-6 md:p-8">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8 border-b dark:border-slate-800 pb-6">
            <h2 className="text-2xl font-black text-gray-800 dark:text-gray-100">Gestionar Banco</h2>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {filteredQuestions.map((q) => (
              <div key={q.id} className="bg-white dark:bg-slate-800 border border-gray-100 dark:border-slate-700 rounded-xl p-5 hover:shadow-md transition-all group">
                <div className="flex justify-between items-start mb-3">
                  <span className="bg-indigo-50 dark:bg-indigo-900/50 text-indigo-600 dark:text-indigo-400 text-[10px] font-black px-2 py-0.5 rounded uppercase tracking-widest">{q.subject}</span>
                  <div className="flex gap-2">
                    <button onClick={() => handleEditExisting(q)} className="p-2 text-indigo-400 hover:bg-indigo-50 dark:hover:bg-slate-700 rounded-lg transition-colors">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                    </button>
                    <button onClick={() => handleDeleteExisting(q.id)} className="p-2 text-gray-300 hover:text-rose-500 rounded-lg transition-colors">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                    </button>
                  </div>
                </div>
                <p className="text-gray-800 dark:text-gray-200 text-sm font-medium mb-4 line-clamp-3 whitespace-pre-wrap">{q.questionText}</p>
                <div className="mt-auto text-[10px] text-gray-400 pt-2 border-t dark:border-slate-700">Tema: {q.topic}</div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminView;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Question, AppDatabase, ViewType, NavigationState, TopicResult, ReadingText } from './types';
import { ACADEMIC_STRUCTURE, DB_STORAGE_KEY } from './constants';
import Navbar from './components/Navbar';
import HomeView from './views/HomeView';
import SubjectsView from './views/SubjectsView';
import TopicsView from './views/TopicsView';
import QuizView from './views/QuizView';
import AdminView from './views/AdminView';
import MegaQuizView from './views/MegaQuizView';

const App: React.FC = () => {
  const [db, setDb] = useState<AppDatabase>(() => {
    const saved = localStorage.getItem(DB_STORAGE_KEY);
    const initial = saved ? JSON.parse(saved) : { questions: [], readingTexts: [] };
    if (!initial.results) initial.results = {};
    if (!initial.readingTexts) initial.readingTexts = [];
    if (initial.totalPracticed === undefined) initial.totalPracticed = 0;
    return initial;
  });

  const [nav, setNav] = useState<NavigationState>({
    view: 'HOME'
  });

  const [isDark, setIsDark] = useState(() => {
    const saved = localStorage.getItem('theme');
    return saved ? saved === 'dark' : true;
  });

  useEffect(() => {
    if (isDark) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDark]);

  useEffect(() => {
    localStorage.setItem(DB_STORAGE_KEY, JSON.stringify(db));
  }, [db]);

  const handleNavigate = useCallback((view: ViewType, params?: Partial<NavigationState>) => {
    setNav(prev => ({ ...prev, view, ...params }));
  }, []);

  const handleBack = useCallback(() => {
    setNav(prev => {
      if (prev.view === 'ADMIN' || prev.view === 'MEGA_QUIZ') return { ...prev, view: 'HOME' };
      if (prev.view === 'QUIZ') return { ...prev, view: 'TOPICS' };
      if (prev.view === 'TOPICS') return { ...prev, view: 'SUBJECTS', selectedTopic: undefined };
      if (prev.view === 'SUBJECTS') return { ...prev, view: 'HOME', selectedSubject: undefined };
      return prev;
    });
  }, []);

  const handleImport = useCallback((data: AppDatabase) => {
    if (!data.results) data.results = {};
    if (!data.readingTexts) data.readingTexts = [];
    if (data.totalPracticed === undefined) data.totalPracticed = 0;
    setDb(data);
    alert('Base de datos importada con éxito.');
  }, []);

  const handleExport = useCallback(() => {
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(db, null, 2));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", `educasani_backup_${new Date().toISOString().split('T')[0]}.json`);
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  }, [db]);

  const saveQuestions = useCallback((newQuestions: Question[]) => {
    setDb(prev => ({
      ...prev,
      questions: [...prev.questions, ...newQuestions]
    }));
  }, []);

  const updateQuestion = useCallback((updatedQ: Question) => {
    setDb(prev => ({
      ...prev,
      questions: prev.questions.map(q => q.id === updatedQ.id ? updatedQ : q)
    }));
  }, []);

  const deleteQuestion = useCallback((id: string) => {
    setDb(prev => ({
      ...prev,
      questions: prev.questions.filter(q => q.id !== id)
    }));
  }, []);

  const saveReadingText = useCallback((text: ReadingText) => {
    setDb(prev => {
      const exists = prev.readingTexts?.find(t => t.id === text.id);
      if (exists) {
        return {
          ...prev,
          readingTexts: prev.readingTexts?.map(t => t.id === text.id ? text : t)
        };
      }
      return {
        ...prev,
        readingTexts: [...(prev.readingTexts || []), text]
      };
    });
  }, []);

  const deleteReadingText = useCallback((id: string) => {
    if (window.confirm("¿Seguro? Se desvincularán las preguntas asociadas.")) {
      setDb(prev => ({
        ...prev,
        readingTexts: prev.readingTexts?.filter(t => t.id !== id),
        questions: prev.questions.map(q => q.readingTextId === id ? { ...q, readingTextId: undefined } : q)
      }));
    }
  }, []);

  const deleteTopic = useCallback((topicName: string, subjectName: string) => {
    if (window.confirm(`¿Seguro que deseas eliminar la práctica "${topicName}"?`)) {
      setDb(prev => {
        const resultKey = `${subjectName}|${topicName}`;
        const newResults = { ...prev.results };
        delete newResults[resultKey];

        return {
          ...prev,
          questions: prev.questions.filter(q => !(q.topic === topicName && q.subject === subjectName)),
          results: newResults
        };
      });
    }
  }, []);

  const moveTopic = useCallback((topicName: string, subjectName: string, direction: 'UP' | 'DOWN') => {
    setDb(prev => {
      const allQuestions = [...prev.questions];
      const subjectQuestions = allQuestions.filter(q => q.subject === subjectName);

      // Get unique topics for this subject
      const uniqueTopicNames = Array.from(new Set(subjectQuestions.map(q => q.topic)));

      // Map them with their current order (first question found)
      const topicsWithOrder = uniqueTopicNames.map(t => ({
        name: t,
        order: subjectQuestions.find(q => q.topic === t)?.order ?? 999
      })).sort((a, b) => a.order - b.order);

      const currentIndex = topicsWithOrder.findIndex(t => t.name === topicName);
      if (currentIndex === -1) return prev;

      const targetIndex = direction === 'UP' ? currentIndex - 1 : currentIndex + 1;
      if (targetIndex < 0 || targetIndex >= topicsWithOrder.length) return prev;

      // Swap names in the array
      const newTopicsOrder = [...topicsWithOrder];
      [newTopicsOrder[currentIndex], newTopicsOrder[targetIndex]] = [newTopicsOrder[targetIndex], newTopicsOrder[currentIndex]];

      // Update the order property of all questions in this subject based on the new array index
      const updatedQuestions = allQuestions.map(q => {
        if (q.subject !== subjectName) return q;
        const newOrder = newTopicsOrder.findIndex(t => t.name === q.topic);
        return { ...q, order: newOrder === -1 ? 999 : newOrder };
      });

      return {
        ...prev,
        questions: updatedQuestions
      };
    });
  }, []);

  const handleFinishQuiz = useCallback((subject: string, topic: string, score: number, total: number) => {
    setDb(prev => ({
      ...prev,
      totalPracticed: (prev.totalPracticed || 0) + total,
      results: {
        ...prev.results,
        [`${subject}|${topic}`]: { score, total }
      }
    }));
  }, []);

  const handleResetPracticed = useCallback(() => {
    if (window.confirm("¿Deseas reiniciar el contador de flashcards practicadas?")) {
      setDb(prev => ({ ...prev, totalPracticed: 0 }));
    }
  }, []);

  const renderView = () => {
    switch (nav.view) {
      case 'HOME':
        return (
          <HomeView 
            onSelectCourse={(course) => handleNavigate('SUBJECTS', { selectedCourse: course })} 
            onStartMegaQuiz={() => handleNavigate('MEGA_QUIZ')}
          />
        );
      case 'SUBJECTS':
        return (
          <SubjectsView 
            courseName={nav.selectedCourse!} 
            onSelectSubject={(subject) => handleNavigate('TOPICS', { selectedSubject: subject })} 
          />
        );
      case 'TOPICS':
        return (
          <TopicsView 
            subjectName={nav.selectedSubject!} 
            questions={db.questions.filter(q => q.subject === nav.selectedSubject)}
            readingTexts={db.readingTexts || []}
            results={db.results || {}}
            onSelectTopic={(topic) => handleNavigate('QUIZ', { selectedTopic: topic })}
            onDeleteTopic={(topic) => deleteTopic(topic, nav.selectedSubject!)}
            onMoveTopic={(topic, dir) => moveTopic(topic, nav.selectedSubject!, dir)}
          />
        );
      case 'QUIZ':
        return (
          <QuizView 
            topicName={nav.selectedTopic!}
            subjectName={nav.selectedSubject!}
            questions={db.questions.filter(q => q.topic === nav.selectedTopic && q.subject === nav.selectedSubject)}
            readingTexts={db.readingTexts || []}
            onFinish={handleFinishQuiz}
          />
        );
      case 'MEGA_QUIZ':
        return (
          <MegaQuizView 
            questions={db.questions}
            readingTexts={db.readingTexts || []}
            onFinishMega={(total) => setDb(prev => ({ ...prev, totalPracticed: (prev.totalPracticed || 0) + total }))}
          />
        );
      case 'ADMIN':
        return (
          <AdminView 
            questions={db.questions}
            readingTexts={db.readingTexts || []}
            onSaveBatch={saveQuestions}
            onUpdateQuestion={updateQuestion}
            onDeleteQuestion={deleteQuestion}
            onSaveReadingText={saveReadingText}
            onDeleteReadingText={deleteReadingText}
          />
        );
      default:
        return <HomeView onSelectCourse={(course) => handleNavigate('SUBJECTS', { selectedCourse: course })} onStartMegaQuiz={() => handleNavigate('MEGA_QUIZ')} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-gray-50 dark:bg-slate-950 transition-colors duration-300">
      <Navbar 
        onNavigate={handleNavigate} 
        onBack={handleBack} 
        onImport={handleImport} 
        onExport={handleExport}
        onResetPracticed={handleResetPracticed}
        currentView={nav.view}
        navState={nav}
        isDark={isDark}
        toggleTheme={() => setIsDark(!isDark)}
        totalPracticed={db.totalPracticed || 0}
      />
      <main className="flex-grow container mx-auto px-4 py-8">
        {renderView()}
      </main>
      <footer className="bg-white dark:bg-slate-900 dark:border-slate-800 border-t py-6 text-center text-sm text-gray-500 dark:text-gray-400">
        &copy; {new Date().getFullYear()} EduCasani • Sistema de Gestión Académica
      </footer>
    </div>
  );
};

